  1→import { Logger, ValidationPipe } from '@nestjs/common';
  2→import { NestFactory } from '@nestjs/core';
  3→import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
  4→import { FastifyRequest, FastifyReply } from 'fastify';
  5→
  6→import { RecoConsoleLogger } from '@config/custom-logger.config';
  7→import { bufferedRollbar } from '@config/rollbar-buffer.config';
  8→
  9→import { AppModule } from '@modules/app/app.module';
 10→import { NewrelicService } from '@modules/newrelic/newrelic.service';
 11→
 12→import { getEnv } from '@utils/get-env-variable.util';
 13→import { setupSwagger } from '@utils/setup-swagger.util';
 14→
 15→import { BadRequestExceptionFilter } from '@middlewares/bad-request-exception.filter';
 16→import { CorrelationIdMiddleware } from '@middlewares/correlation-id.middleware';
 17→import { RollbarExceptionFilter } from '@middlewares/exceptions.filter';
 18→import { fastifyHttpLogger } from '@middlewares/logger.middleware';
 19→
 20→import {
 21→	NODE_ENV,
 22→	PORT,
 23→	SERVER_NAME,
 24→	GLOBAL_PREFIX,
 25→	IS_COMPACT_LOGS,
 26→	IS_JSON_LIKE_LOGS,
 27→} from '@constants/env-variables.constant';
 28→
 29→import { Environment } from '@interfaces/env-variables.interface';
 30→
 31→import { NewrelicInterceptor } from '@interceptors/newrelic.interceptor';
 32→
 33→declare const module: {
 34→	hot?: { accept: () => void; dispose: (callback: () => void) => void };
 35→};
 36→
 37→async function bootstrap(): Promise<NestFastifyApplication> {
 38→	const globalPrefix = getEnv<string>({ key: GLOBAL_PREFIX });
 39→	const port = getEnv<number>({ key: PORT, converter: Number });
 40→	const nodeEnv = getEnv<Environment>({ key: NODE_ENV });
 41→	const serverName = getEnv<string>({ key: SERVER_NAME });
 42→	const isCompactLogs = getEnv<boolean>({ key: IS_COMPACT_LOGS, converter: Boolean });
 43→	const isJsonLikeLogs = getEnv<boolean>({ key: IS_JSON_LIKE_LOGS, converter: Boolean });
 44→	const isDev = nodeEnv === Environment.DEVELOPMENT;
 45→	const isProdOrStaging =
 46→		nodeEnv === Environment.PRODUCTION || nodeEnv === Environment.STAGING;
 47→
 48→	const logger = new RecoConsoleLogger({
 49→		logLevels: isDev
 50→			? ['log', 'error', 'warn', 'fatal', 'debug', 'verbose']
 51→			: ['log', 'error', 'warn', 'fatal'],
 52→		colors: isDev,
 53→		prefix: serverName,
 54→		compact: isCompactLogs,
 55→		json: isJsonLikeLogs,
 56→	});
 57→
 58→	const fastifyAdapter = new FastifyAdapter({
 59→		trustProxy: true,
 60→	});
 61→	fastifyAdapter.getInstance().register(fastifyHttpLogger);
 62→
 63→	const app = await NestFactory.create<NestFastifyApplication>(
 64→		AppModule,
 65→		fastifyAdapter,
 66→		{ bodyParser: false, rawBody: true, logger },
 67→	);
 68→
 69→	if (nodeEnv !== Environment.PRODUCTION) {
 70→		setupSwagger({ app, fastifyAdapter, globalPrefix });
 71→	}
 72→
 73→	app.enableCors({ origin: true, credentials: true });
 74→
 75→	app.use((req: FastifyRequest['raw'], res: FastifyReply['raw'], next: () => void) => {
 76→		const middleware = new CorrelationIdMiddleware();
 77→		middleware.use(req, res, next);
 78→	});
 79→
 80→	if (isProdOrStaging) {
 81→		app.useGlobalInterceptors(
 82→			new NewrelicInterceptor(await app.resolve<NewrelicService>(NewrelicService)),
 83→		);
 84→		app.useGlobalFilters(new RollbarExceptionFilter());
 85→	}
 86→
 87→	app.useGlobalFilters(new BadRequestExceptionFilter());
 88→
 89→	app.useGlobalPipes(
 90→		new ValidationPipe({ transform: true, whitelist: true, forbidNonWhitelisted: true }),
 91→	);
 92→
 93→	app.setGlobalPrefix(globalPrefix, {
 94→		exclude: ['is_it_up', 'is_it_working', 'is_it_ready', 'robots.txt'],
 95→	});
 96→
 97→	if (!isDev) {
 98→		app.enableShutdownHooks();
 99→	}
100→
101→	logger.log(`[Main file] Application is running on ${String(port)} port`);
102→	await app.listen(port, '0.0.0.0');
103→
104→	if (!isDev) {
105→		const LogShutDown = ({ signal }: { signal: string }): void => {
106→			logger.log(`Received ${signal} server is shutting down`);
107→		};
108→		process.on('SIGINT', () => {
109→			LogShutDown({ signal: 'SIGINT' });
110→		});
111→		process.on('SIGTERM', () => {
112→			LogShutDown({ signal: 'SIGTERM' });
113→		});
114→	}
115→
116→	return app;
117→}
