377→	protected stringifyMessage(message: unknown, logLevel: LogLevel): string {
378→		if (isFunction(message)) {
379→			const messageAsStr = Function.prototype.toString.call(message);
380→			const isClass = messageAsStr.startsWith('class ');
381→			if (isClass) {
382→				// @ts-ignore
383→				return this.stringifyMessage(message.name, logLevel);
384→			}
385→			// @ts-ignore
386→			return this.stringifyMessage(message(), logLevel);
387→		}
388→
389→		if (typeof message === 'string') {
390→			return this.colorize(message, logLevel);
391→		}
392→
393→		const outputText = inspect(message, this.inspectOptions);
394→		if (isPlainObject(message)) {
395→			return `Object(${Object.keys(message).length}) ${outputText}`;
396→		}
397→		if (Array.isArray(message)) {
398→			return `Array(${message.length}) ${outputText}`;
399→		}
