 66→	private async applyColorMatching(
 67→		products: IRelatedProduct[],
 68→		mvRecords: Map<number, IStylesMvBase>,
 69→		currentStyleColor: IStyleColorBase,
 70→	): Promise<IRelatedProduct[]> {
 71→		const colorCache = new Map<
 72→			number,
 73→			ReturnType<typeof this.productHydrationService.convertMvColorsToProductColors>
 74→		>();
 75→
