 38→	private async getCurrentColorStyle(styleId?: number): Promise<IStyleColorBase | null> {
 39→		if (!styleId) {
 40→			return null;
 41→		}
 42→
 43→		const currentStyle = await this.styleColorsService.getStyleByStyleId({
 44→			styleId: Number(styleId),
 45→		});
 46→
 47→		if (!currentStyle) {
