244→	private selectRandomStylesFromCategoriesGeneric<
245→		T extends { style_id: number } & Partial<Record<K, number>>,
246→		K extends string,
247→	>(styles: T[], categoryIds: number[], categoryKey: K, categoryLabel: string): number[] {
248→		if (categoryIds.length === 0) {
249→			return [];
250→		}
251→
252→		const stylesByCategory: Record<number, T[]> = {};
253→		for (const style of styles) {
254→			const categoryId = style[categoryKey];
255→			if (categoryId !== undefined) {
256→				// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
257→				stylesByCategory[categoryId] ??= [];
258→				stylesByCategory[categoryId].push(style);
259→			}
260→		}
261→
262→		const selectedStyles: number[] = [];
263→
264→		for (const categoryId of categoryIds) {
265→			const categoryStyles = stylesByCategory[categoryId];
266→			this.logger.debug(`${categoryLabel} has styles`, {
267→				categoryId,
268→				styleCount: categoryStyles?.length ?? 0,
269→			});
270→			if (categoryStyles && categoryStyles.length > 0) {
271→				const randomIndex = Math.floor(Math.random() * categoryStyles.length);
272→				const styleId = categoryStyles[randomIndex]?.style_id;
273→				if (styleId) {
274→					selectedStyles.push(styleId);
275→					this.logger.debug(`Selected style from ${categoryLabel.toLowerCase()}`, {
276→						styleId,
277→						categoryId,
278→					});
279→				}
280→			} else {
281→				this.logger.warn(`No styles found for ${categoryLabel.toLowerCase()}`, {
282→					categoryId,
283→				});
284→			}
285→		}
286→
287→		return selectedStyles;
288→	}
