214→	public forecastStyleTrend({
215→		styleId,
216→		historicalData,
217→		startDate,
218→		endDate,
219→		forecastDays,
220→		bar,
221→	}: {
222→		styleId: number;
223→		historicalData: IProductAnnualSalesBase[];
224→		startDate: string;
225→		endDate: string;
226→		forecastDays: number;
227→		bar?: ProgressBar;
228→	}): CompleteForecastResult | null {
229→		try {
230→			const endDateDayNumber = this.getDayOfYear(new Date(endDate));
231→
232→			const purchasesArr = historicalData.reduce<number[]>((acc, data, index) => {
233→				if (index === historicalData.length - 1) {
234→					acc.push(...data.daily_orders.slice(0, endDateDayNumber));
235→				} else {
236→					acc.push(...data.daily_orders);
237→				}
238→				return acc;
239→			}, []);
240→
241→			const smoothedPurchasesArr = MathematicalFunctions.exponentialSmoothing({
242→				values: purchasesArr,
243→				alpha: 0.1,
244→			});
245→
246→			const harmonics = this.getHarmonicsByObservationsCount({
247→				observations: smoothedPurchasesArr.length,
248→			});
249→
250→			const changes = MathematicalFunctions.changePointDetection({
251→				values: smoothedPurchasesArr,
252→				significance: 0.02,
253→				penalty: 0.1,
254→				minSegmentLength: 40,
255→			});
256→
257→			const yearlyComponent = this.calculateSeasonalComponent({
258→				values: smoothedPurchasesArr,
259→				period: 365,
260→				harmonics,
261→			});
262→
263→			const monthlyComponent = this.calculateSeasonalComponent({
264→				values: smoothedPurchasesArr,
265→				period: 30,
266→				harmonics,
267→			});
268→
269→			const weeklyComponent = this.calculateSeasonalComponent({
270→				values: smoothedPurchasesArr,
271→				period: 7,
272→				harmonics,
273→			});
274→
275→			const quarterlyComponent = this.calculateSeasonalComponent({
276→				values: smoothedPurchasesArr,
277→				period: 91,
278→				harmonics,
279→			});
280→
281→			const trendComponent = this.calculateTrendComponent({
282→				values: smoothedPurchasesArr,
283→				changePoints: changes.changePoints,
284→				startDate: startDate,
285→				endDate: endDate,
286→			});
287→
288→			const residuals = purchasesArr.map((val, i) => {
289→				const trend = trendComponent[i] ?? 0;
290→				const yearly = yearlyComponent[i] ?? 0;
291→				const monthly = monthlyComponent[i] ?? 0;
292→				const weekly = weeklyComponent[i] ?? 0;
293→				const quarterly = quarterlyComponent[i] ?? 0;
294→				return val - (trend + yearly + monthly + weekly + quarterly);
295→			});
296→
297→			const smoothedResidualsArr = MathematicalFunctions.exponentialSmoothing({
298→				values: residuals,
299→				alpha: 0.1,
300→			});
301→
302→			const comprehensiveForecast = this.createComprehensiveForecast({
303→				yearlyComponent,
304→				monthlyComponent,
305→				weeklyComponent,
306→				quarterlyComponent,
307→				trendComponent,
308→				smoothedResidualsArr,
309→				historicalLength: purchasesArr.length,
310→				forecastDays,
311→				endDate,
312→				purchasesArr,
313→			});
314→
315→			const historicalWindow = 14;
316→			const historicalOrders = purchasesArr.slice(-historicalWindow);
317→
318→			const trendingScoreData = {
319→				historicalOrders,
320→				forecastedOrders: comprehensiveForecast.forecastValues,
321→				trendComponent,
322→			};
323→
324→			const trendingResult =
325→				TrendingScoreCalculator.calculateTrendingScore(trendingScoreData);
326→
327→			const trendScore = trendingResult.trendScore;
328→
329→			const { trendingReason } = this.calculateTrendingReason({
330→				comprehensiveForecast,
331→				historicalOrders,
332→				trendComponent,
333→			});
334→
335→			const finalTrendingReason = trendingReason;
336→
337→			const forecastResult: CompleteForecastResult = {
338→				style_id: styleId,
339→				forecast_dates: comprehensiveForecast.forecastDates,
340→				predicted_orders: comprehensiveForecast.forecastValues,
341→				trend_score: Math.round(trendScore * 100) / 100,
342→				trending_reason: finalTrendingReason,
343→				purchasesArr,
344→				smoothedPurchasesArr,
345→				yearlyComponent,
346→				monthlyComponent,
347→				weeklyComponent,
348→				quarterlyComponent,
349→				trendComponent,
350→				smoothedResidualsArr,
351→				comprehensiveForecast,
352→				changes,
353→				startDate,
354→				endDate,
355→			};
356→
357→			if (bar) {
358→				bar.increment({ by: 1 });
359→			}
360→
361→			return forecastResult;
362→		} catch (error) {
363→			this.logger.error(
364→				`Error processing product ${styleId}: ${(error as Error).message}`,
365→				(error as Error).stack,
366→			);
367→			if (bar) {
368→				bar.increment({ by: 1 });
369→			}
370→			return null;
371→		}
372→	}
