439→	private calculateSeasonalComponent({
440→		values,
441→		period,
442→		harmonics,
443→	}: {
444→		values: number[];
445→		period: number;
446→		harmonics: number;
447→	}): number[] {
448→		const n = values.length;
449→		if (n < period) {
450→			return new Array(n).fill(0) as number[];
451→		}
452→
453→		try {
454→			const coefficients = MathematicalFunctions.fourierCoefficients({
455→				values,
456→				period,
457→				harmonics,
458→				precision: null,
459→			});
460→
461→			const seasonal = MathematicalFunctions.reconstructFourierSeries({
462→				period,
463→				harmonics,
464→				a: coefficients.a,
465→				b: coefficients.b,
466→				length: n,
467→			});
468→
469→			return seasonal;
470→		} catch (error) {
471→			this.logger.error(
472→				`Error extending seasonal component: ${(error as Error).message}`,
473→				(error as Error).stack,
474→			);
475→			return values.map((_, index) => {
476→				const cyclePosition = index % Math.max(1, Math.floor(period));
477→				const seasonalIndex = Math.min(cyclePosition, values.length - 1);
478→				return values[seasonalIndex] ? values[seasonalIndex] * 0.1 : 0;
479→			});
480→		}
481→	}
482→
483→	private calculateTrendComponent({
484→		values,
485→		changePoints,
486→		startDate,
487→		endDate,
488→	}: {
489→		values: number[];
490→		changePoints: number[];
491→		startDate: string;
492→		endDate: string;
493→	}): number[] {
494→		const n = values.length;
495→		if (n === 0) return [];
496→
497→		const dates = this.generateDateRange(startDate, endDate, n);
498→
499→		if (changePoints.length === 0) {
500→			return MathematicalFunctions.calculateTrend({ values, dates });
501→		}
502→
503→		const trend = new Array(n).fill(0) as number[];
504→		const segments = [0, ...changePoints, n];
505→
506→		for (let i = 0; i < segments.length - 1; i++) {
507→			const start = segments[i] as unknown as number;
508→			const end = segments[i + 1] as unknown as number;
509→			const segmentValues = values.slice(start, end);
510→			const segmentDates = dates.slice(start, end);
511→
512→			if (segmentValues.length > 1) {
513→				const segmentTrend = MathematicalFunctions.calculateTrend({
514→					values: segmentValues,
515→					dates: segmentDates,
516→				});
517→
518→				for (let j = 0; j < segmentTrend.length; j++) {
519→					trend[start + j] = segmentTrend[j] as unknown as number;
520→				}
521→			} else if (segmentValues.length === 1) {
522→				trend[start] = segmentValues[0] as unknown as number;
523→			}
524→		}
525→
526→		return trend;
527→	}
