545→	private createComprehensiveForecast({
546→		yearlyComponent,
547→		monthlyComponent,
548→		weeklyComponent,
549→		quarterlyComponent,
550→		trendComponent,
551→		smoothedResidualsArr,
552→		historicalLength,
553→		forecastDays,
554→		endDate,
555→	}: {
556→		yearlyComponent: number[];
557→		monthlyComponent: number[];
558→		weeklyComponent: number[];
559→		quarterlyComponent: number[];
560→		trendComponent: number[];
561→		smoothedResidualsArr: number[];
562→		historicalLength: number;
563→		forecastDays: number;
564→		endDate: string;
565→		purchasesArr: number[];
566→	}): {
567→		forecastValues: number[];
568→		forecastDates: string[];
569→		components: {
570→			yearly: number[];
571→			monthly: number[];
572→			weekly: number[];
573→			quarterly: number[];
574→			trend: number[];
575→			residuals: number[];
576→		};
577→	} {
578→		const forecastDates = this.generateFutureDates(endDate, forecastDays);
579→
580→		const harmonics = this.getHarmonicsByObservationsCount({
581→			observations: historicalLength,
582→		});
583→
584→		const extendedYearly = this.extendSeasonalComponent(
585→			yearlyComponent,
586→			365,
587→			harmonics,
588→			historicalLength,
589→			forecastDates,
590→			endDate,
591→		);
592→		const extendedMonthly = this.extendSeasonalComponent(
593→			monthlyComponent,
594→			30,
595→			harmonics,
596→			historicalLength,
597→			forecastDates,
598→			endDate,
599→		);
600→		const extendedWeekly = this.extendSeasonalComponent(
601→			weeklyComponent,
602→			7,
603→			harmonics,
604→			historicalLength,
605→			forecastDates,
606→			endDate,
607→		);
608→		const extendedQuarterly = this.extendSeasonalComponent(
609→			quarterlyComponent,
610→			91,
611→			harmonics,
612→			historicalLength,
613→			forecastDates,
614→			endDate,
615→		);
616→
617→		const extendedResiduals = this.extendResidualsComponent({
618→			smoothedResidualsArr,
619→			forecastDays,
620→			endDate,
621→		});
622→
623→		const extendedTrend = this.extendTrendComponent(trendComponent, forecastDays);
624→
625→		const forecastValues = Array(forecastDays)
626→			.fill(0)
627→			.map((_, i) => {
628→				const yearly = extendedYearly[i] ?? 0;
629→				const monthly = extendedMonthly[i] ?? 0;
630→				const weekly = extendedWeekly[i] ?? 0;
631→				const quarterly = extendedQuarterly[i] ?? 0;
632→				const trend = extendedTrend[i] ?? 0;
633→				const residual = extendedResiduals[i] ?? 0;
634→				const forecastValue = trend + yearly + monthly + weekly + quarterly + residual;
635→				return Math.max(0, forecastValue);
636→			});
637→
638→		return {
639→			forecastValues,
640→			forecastDates,
641→			components: {
642→				yearly: extendedYearly,
643→				monthly: extendedMonthly,
644→				weekly: extendedWeekly,
645→				quarterly: extendedQuarterly,
646→				trend: extendedTrend,
647→				residuals: extendedResiduals,
648→			},
649→		};
650→	}
