661→	private extendSeasonalComponent(
662→		component: number[],
663→		period: number,
664→		harmonics: number,
665→		historicalLength: number,
666→		forecastDates: string[],
667→		endDate: string,
668→	): number[] {
669→		if (component.length === 0) return Array(forecastDates.length).fill(0) as number[];
670→
671→		try {
672→			const coefficients = MathematicalFunctions.fourierCoefficients({
673→				values: component,
674→				period,
675→				harmonics,
676→				precision: null,
677→			});
678→
679→			const forecastValues: number[] = [];
680→			const endDateObj = new Date(endDate);
681→
682→			for (const forecastDate of forecastDates) {
683→				const forecastDateObj = new Date(forecastDate);
684→
685→				const daysDiff = Math.floor(
686→					(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
687→				);
688→
689→				const cyclePosition = (historicalLength + daysDiff) % period;
690→				const singlePointSeries = MathematicalFunctions.reconstructFourierSeries({
691→					period,
692→					harmonics,
693→					a: coefficients.a,
694→					b: coefficients.b,
695→					length: Math.ceil(cyclePosition) + 1,
696→					a0: 0,
697→				});
698→
699→				const seasonalValue = singlePointSeries[Math.floor(cyclePosition)] ?? 0;
700→				forecastValues.push(seasonalValue);
701→			}
702→
703→			return forecastValues;
704→		} catch (error) {
705→			this.logger.error(
706→				`Error extending seasonal component: ${(error as Error).message}`,
707→				(error as Error).stack,
708→			);
709→			return forecastDates.map((forecastDate) => {
710→				const endDateObj = new Date(endDate);
711→				const forecastDateObj = new Date(forecastDate);
712→				const daysDiff = Math.floor(
713→					(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
714→				);
715→				const flooredPeriod = Math.max(1, Math.floor(period));
716→				const cyclePosition = (historicalLength + daysDiff) % flooredPeriod;
717→				const historicalIndex = Math.min(cyclePosition, component.length - 1);
718→				return component[historicalIndex] ?? 0;
719→			});
720→		}
721→	}
722→
723→	private extendTrendComponent(trendComponent: number[], forecastDays: number): number[] {
724→		if (trendComponent.length < 2) return Array(forecastDays).fill(0) as number[];
725→
726→		const recentTrendPoints = Math.min(30, trendComponent.length);
727→		const recentTrend = trendComponent.slice(-recentTrendPoints);
728→
729→		const x = Array.from({ length: recentTrend.length }, (_, i) => i);
730→		const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });
731→
732→		const lastValue = trendComponent[trendComponent.length - 1] ?? 0;
733→		const trendSlope = regression.slope;
734→
735→		return Array(forecastDays)
736→			.fill(0)
737→			.map((_, i) => {
738→				const decay = Math.exp(-0.02 * i);
739→				return lastValue + trendSlope * (i + 1) * decay;
740→			});
741→	}
742→
743→	private extendResidualsComponent({
744→		smoothedResidualsArr,
745→		forecastDays,
746→		endDate,
747→	}: {
748→		smoothedResidualsArr: number[];
749→		forecastDays: number;
750→		endDate: string;
751→	}): number[] {
752→		if (smoothedResidualsArr.length === 0 || forecastDays <= 0) {
753→			return Array(forecastDays).fill(0) as number[];
754→		}
755→
756→		const twoWeeksLength = 7;
757→		const trendLength = Math.min(twoWeeksLength, smoothedResidualsArr.length);
758→		const recentResiduals = smoothedResidualsArr.slice(-trendLength);
759→
760→		const endDateObj = new Date(endDate);
761→		const dates = recentResiduals.map((_, i) => {
762→			const date = new Date(endDateObj);
763→			date.setDate(endDateObj.getDate() - (trendLength - i - 1));
764→			const dateArr = date.toISOString().split('T') as [string, string];
765→			return dateArr[0];
766→		});
767→
768→		const trendValues = MathematicalFunctions.calculateTrend({
769→			values: recentResiduals,
770→			dates,
771→		});
772→
773→		if (trendValues.length === 0) {
774→			return Array(forecastDays).fill(0) as number[];
775→		}
776→
777→		const x = Array.from({ length: recentResiduals.length }, (_, i) => i);
778→		const regression = MathematicalFunctions.linearRegression({ x, y: recentResiduals });
779→
780→		const lastIndex = recentResiduals.length - 1;
781→		return Array(forecastDays)
782→			.fill(0)
783→			.map((_, i) => {
784→				return regression.slope * (lastIndex + i + 1) + regression.intercept;
785→			});
786→	}
787→
788→	private getDayOfYear(date = new Date()) {
789→		const start = new Date(Date.UTC(date.getFullYear(), 0, 1));
790→		const current = new Date(
791→			Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()),
792→		);
793→
794→		return Math.floor((current.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
795→	}
796→
797→	private generateFutureDates(endDate: string, forecastDays: number): string[] {
798→		const dates: string[] = [];
799→		const startDate = new Date(endDate);
800→
801→		for (let i = 1; i <= forecastDays; i++) {
802→			const futureDate = new Date(startDate);
803→			futureDate.setDate(startDate.getDate() + i);
804→			const dateArr = futureDate.toISOString().split('T') as [string, string];
805→			dates.push(dateArr[0]);
806→		}
807→
808→		return dates;
809→	}
810→
811→	private calculateTrendingReason({
812→		comprehensiveForecast,
813→		historicalOrders,
814→		trendComponent,
815→	}: {
816→		comprehensiveForecast: {
817→			forecastValues: number[];
818→			forecastDates: string[];
819→			components: {
820→				yearly: number[];
821→				monthly: number[];
822→				weekly: number[];
823→				quarterly: number[];
824→				trend: number[];
825→				residuals: number[];
826→			};
827→		};
828→		historicalOrders: number[];
829→		trendComponent: number[];
830→	}): { trendingReason: string; growthRate: number } {
831→		if (
832→			historicalOrders.length === 0 ||
833→			comprehensiveForecast.forecastValues.length === 0
834→		) {
835→			return { trendingReason: 'Stable pattern', growthRate: 0 };
836→		}
837→
838→		const historicalAvg =
839→			historicalOrders.reduce((sum, val) => sum + val, 0) / historicalOrders.length;
840→		const forecastAvg =
841→			comprehensiveForecast.forecastValues.reduce((sum, val) => sum + val, 0) /
842→			comprehensiveForecast.forecastValues.length;
843→
844→		const growthRate =
845→			historicalAvg > 0 ? (forecastAvg - historicalAvg) / historicalAvg : 0;
846→
847→		const trendSlope = this.calculateTrendSlope(trendComponent);
848→
849→		if (growthRate > 0.2 || forecastAvg > historicalAvg * 1.2) {
850→			return { trendingReason: 'Strong growth forecast', growthRate };
851→		} else if (growthRate > 0.1 || forecastAvg > historicalAvg * 1.1) {
852→			return { trendingReason: 'Moderate growth forecast', growthRate };
853→		} else if (growthRate > 0 || trendSlope >= 0.05) {
854→			return { trendingReason: 'Positive trend detected', growthRate };
855→		} else {
856→			return { trendingReason: 'Stable pattern', growthRate };
857→		}
858→	}
859→
860→	private calculateTrendSlope(trendComponent: number[]): number {
861→		if (trendComponent.length < 2) return 0;
862→
863→		const recentPoints = Math.min(14, trendComponent.length);
864→		const recentTrend = trendComponent.slice(-recentPoints);
865→
866→		const x = Array.from({ length: recentTrend.length }, (_, i) => i);
867→		const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });
868→
869→		return regression.slope;
870→	}
871→}
