235→				return [];
236→			}
237→
238→			const results = await this.algoliaClient.getObjects({
239→				requests: objectIDs.map((objectID) => ({
240→					indexName: this.indexName,
241→					objectID: `${objectID}-${ALGOLIA_OBJECT_ID_SUFFIXES[0]}`,
242→				})),
243→			});
244→
245→			return results.results.filter(
246→				(result): result is AlgoliaRelatedProductHit => result !== null,
247→			);
248→		} catch (error: unknown) {
249→			this.handleError({
250→				context: `Error fetching multiple objects from Algolia with IDs: ${objectIDs.join(', ')}`,
251→				error,
252→			});
253→			throw new Error(`Failed to fetch multiple objects from Algolia`);
254→		}
