257→	generateAlgoliaRelatedProductKey({ productId }: { productId: string }): string {
258→		return `style:${productId}`;
259→	}
260→
261→	public async getRelatedProductIds({
262→		productId,
263→	}: {
264→		productId: number;
265→	}): Promise<number[]> {
266→		try {
267→			const objectIdKey = `${productId}-${ALGOLIA_OBJECT_ID_SUFFIXES[0]}`;
268→			const cacheKey = `ids:${this.generateAlgoliaRelatedProductKey({ productId: objectIdKey })}`;
269→			const cachedIds = await this.cacheService.get<number[]>({
270→				namespace: Namespaces.RELATED_ITEMS_MODEL,
271→				key: cacheKey,
272→			});
273→
274→			if (cachedIds) {
275→				this.logger.log('Cache hit for related product IDs', { productId, objectIdKey });
276→				await this.metricsService.incrementDailyCounter({
277→					metricType: dailyTrackingKeys.CACHE_REQUESTS,
278→				});
279→				return cachedIds;
280→			}
281→
282→			this.logger.log('Cache miss for related product IDs', { productId, objectIdKey });
283→
284→			const results = await this.algoliaClientRecommend.getRecommendations({
285→				requests: [
286→					{
287→						indexName: this.indexName,
288→						model: 'related-products',
289→						threshold: 0,
290→						objectID: objectIdKey,
291→					},
292→				],
293→			});
294→
295→			const recommendationsHits = results.results[0]?.hits ?? [];
296→			const styleIds = recommendationsHits
297→				.map((hit) => {
298→					const productIdValue = (hit as unknown as AlgoliaRelatedProductHit).product_id;
299→					return typeof productIdValue === 'string'
300→						? Number(productIdValue)
301→						: productIdValue;
302→				})
303→				.filter((id): id is number => !isNaN(id));
304→
305→			await this.metricsService.incrementDailyCounter({
306→				metricType: dailyTrackingKeys.ALGOLIA_REQUESTS,
307→			});
308→			this.logger.log('Fetched related product IDs from Algolia', {
309→				productId,
310→				objectIdKey,
311→				count: styleIds.length,
312→			});
313→
314→			await this.cacheService.set({
315→				namespace: Namespaces.RELATED_ITEMS_MODEL,
316→				key: cacheKey,
317→				value: styleIds,
318→				ttl: this.relatedProductsCacheTtl,
319→			});
320→
321→			return styleIds;
322→		} catch (error: unknown) {
323→			this.handleError({
324→				context: `Error fetching related product IDs from Algolia for productId ${productId}`,
325→				error,
326→			});
327→			if ((error as Error).message !== 'ObjectID does not exist') {
328→				bufferedRollbar.error({ err: error as Error, context: { productId } });
329→			}
330→			throw new Error(`Failed to fetch related product IDs for productId ${productId}`);
331→		}
332→	}
333→
334→	async getProductsByMultipleBrands({
335→		brands,
336→		limit = 100,
337→		categoryId,
338→	}: {
339→		brands: string[];
340→		limit?: number;
341→		categoryId?: number | undefined;
342→	}): Promise<AlgoliaRelatedProductHit[]> {
343→		try {
344→			if (brands.length === 0) {
345→				return [];
346→			}
347→
348→			const brandFilters = brands.map((brand) => `brand:"${brand}"`).join(' OR ');
349→			const suffixFilter = `index_suffix:"${ALGOLIA_OBJECT_ID_SUFFIXES[0]}"`;
350→			const categoryFilter = categoryId ? `primary_category_id:${categoryId}` : '';
351→			const combinedFilters = categoryFilter
352→				? `(${brandFilters}) AND ${categoryFilter} AND ${suffixFilter}`
353→				: `(${brandFilters}) AND ${suffixFilter}`;
354→
355→			const result = await this.algoliaClient.searchForHits({
356→				requests: [
357→					{ indexName: this.indexName, filters: combinedFilters, hitsPerPage: limit },
358→				],
359→			});
360→
361→			return (result.results[0]?.hits ?? []) as unknown as AlgoliaRelatedProductHit[];
362→		} catch (error: unknown) {
363→			this.handleError({
364→				context: `Error fetching products for brands: ${brands.join(', ')}`,
365→				error,
366→			});
367→			throw new Error(`Failed to fetch products for multiple brands`);
368→		}
369→	}
370→}
