127→			return { addons: shuffleArray({ array: result.addons }) };
128→		} catch (error) {
129→			if (error instanceof NotFoundException) {
130→				throw error;
131→			}
132→
133→			const err = error instanceof Error ? error : new Error(String(error));
134→			this.logger.error(`Error fetching curated addons: ${err.message}`, err.stack);
135→			throw err;
136→		}
137→	}
