 21→import { EmailRecommendationsResponseDto } from '@dto/email-recommendations/email-recommendations-response.dto';
 22→
 23→interface IEmailRecommendationRawResult {
 24→	recommendations: Map<number, IRelatedProduct[]>;
 25→	fallbackUsed: boolean;
 26→	fallbackReason?: string;
 27→	categoryIds?: number[];
 28→}
 29→const DEFAULT_LIMIT_FOR_EMAILS_RECOMMENDATIONS = 6;
 30→@Injectable()
 31→export class EmailRecommendationsService {
 32→	private readonly logger = new Logger(EmailRecommendationsService.name);
 33→
 34→	// TODO: Fallback products for edge cases, need to take from merchandise team
 35→	private readonly FALLBACK_PRODUCTS = [
