 42→	constructor(
 43→		private readonly frequentlyBoughtTogetherService: FrequentlyBoughtTogetherService,
 44→		private readonly productHydrationService: ProductHydrationService,
 45→		private readonly relatedProductsService: RelatedProductsService,
 46→		private readonly trendingProductsService: TrendingProductsService,
 47→		private readonly stylesService: StylesService,
 48→		private readonly styleColorsService: StyleColorsService,
 49→	) {}
 50→
 51→	private async resolveProductIds({
 52→		products,
 53→	}: {
 54→		products: { productId?: number; colorId?: number }[] | undefined;
 55→	}): Promise<{ productId: number; colorId?: number }[]> {
 56→		if (!products || products.length === 0) {
 57→			this.logger.log('[resolveProductIds] No products to resolve', { products });
 58→			return [];
 59→		}
 60→
 61→		this.logger.log('[resolveProductIds] Starting resolution', {
 62→			inputCount: products.length,
 63→		});
 64→		const resolvedProducts: { productId: number; colorId?: number }[] = [];
 65→
 66→		for (const product of products) {
 67→			if (product.productId) {
 68→				const resolvedProduct: { productId: number; colorId?: number } = {
 69→					productId: product.productId,
 70→				};
 71→				if (product.colorId) {
 72→					resolvedProduct.colorId = product.colorId;
 73→				}
 74→				resolvedProducts.push(resolvedProduct);
 75→			} else if (product.colorId) {
 76→				try {
 77→					const styleColor = await this.styleColorsService.getStyleByColorId({
 78→						colorId: product.colorId,
 79→					});
 80→
 81→					if (!styleColor) {
 82→						this.logger.warn('Could not find style for colorId', {
 83→							colorId: product.colorId,
 84→						});
 85→						continue;
 86→					}
 87→
 88→					const productId = Number(styleColor.style_id);
 89→					if (isNaN(productId)) {
 90→						this.logger.warn('Invalid style_id for colorId', {
 91→							styleId: styleColor.style_id,
 92→							colorId: product.colorId,
 93→						});
 94→						continue;
 95→					}
 96→
 97→					resolvedProducts.push({
 98→						productId,
 99→						colorId: product.colorId,
100→					});
101→				} catch (error) {
102→					this.logger.warn(
103→						`Error resolving productId from colorId ${product.colorId}: ${error}`,
104→					);
105→				}
106→			}
107→		}
108→
109→		return resolvedProducts;
110→	}
111→
112→	@LogExecution({
113→		paramFormatter: ([{ query }]: [{ query: EmailRecommendationsQueryDto }]) => ({
114→			types: query.types,
115→			productCount: query.products?.length ?? 0,
116→			limit: query.limit,
117→			blendStrategy: query.blendStrategy,
118→		}),
119→		responseFormatter: (res: EmailRecommendationsResponseDto) => ({
120→			fbtCount: res.fbt_products?.length ?? 0,
121→			similarCount: res.similar_products?.length ?? 0,
122→			trendingCount: res.trending_products?.length ?? 0,
123→			fallbackUsed: res.fallback_used ?? false,
124→		}),
125→	})
126→	async getEmailRecommendations({
127→		query,
128→	}: {
129→		query: EmailRecommendationsQueryDto;
130→	}): Promise<EmailRecommendationsResponseDto> {
131→		const {
132→			types,
133→			products,
134→			limit = DEFAULT_LIMIT_FOR_EMAILS_RECOMMENDATIONS,
135→			blendStrategy = BlendStrategy.RATING,
136→		} = query;
137→
138→		const resolvedProducts = await this.resolveProductIds({ products });
139→
140→		// Default to all types if none specified
141→		const requestedTypes =
142→			types && types.length > 0
143→				? types
144→				: [
145→						RecommendationType.FBT,
146→						RecommendationType.SIMILAR,
147→						RecommendationType.TRENDING,
148→					];
149→
150→		this.logger.log('Getting email recommendations', {
151→			types: requestedTypes,
152→			productCount: resolvedProducts.length,
153→			limit,
154→		});
155→
156→		try {
157→			const response: EmailRecommendationsResponseDto = {};
158→			const fallbackReasons: Record<string, string> = {};
159→			let anyFallbackUsed = false;
160→			let categoryIds: number[] = [];
161→
162→			for (const type of requestedTypes) {
163→				if (!Object.values(RecommendationType).includes(type)) {
164→					this.logger.warn('Unsupported recommendation type', { type });
165→					continue;
166→				}
167→
168→				const result = await this.getRecommendationsByType({
169→					type,
170→					products: resolvedProducts,
171→					limit,
172→					blendStrategy,
173→				});
174→
175→				switch (type) {
176→					case RecommendationType.FBT:
177→						response.fbt_products = result.recommendations;
178→						break;
179→					case RecommendationType.SIMILAR:
180→						response.similar_products = result.recommendations;
181→						break;
182→					case RecommendationType.TRENDING:
183→						response.trending_products = result.recommendations;
184→						break;
185→				}
186→
187→				if (result.fallbackUsed && result.fallbackReason) {
188→					anyFallbackUsed = true;
189→					fallbackReasons[type] = result.fallbackReason;
190→				}
191→
192→				if (result.categoryIds && result.categoryIds.length > 0) {
193→					categoryIds = result.categoryIds;
194→				}
195→			}
196→
197→			if (resolvedProducts.length > 0) {
198→				response.source_product_ids = resolvedProducts.map((p) => p.productId);
199→			}
200→			if (categoryIds.length > 0) {
201→				response.category_ids = categoryIds;
202→			}
203→			if (anyFallbackUsed) {
204→				response.fallback_used = true;
205→				response.fallback_reasons = fallbackReasons;
206→			}
207→
208→			return response;
209→		} catch (error) {
210→			this.logger.error(
211→				`Error getting email recommendations: ${(error as Error).message}`,
212→				(error as Error).stack,
213→			);
214→			throw error;
215→		}
216→	}
217→
218→	private async getRecommendationsByType({
219→		type,
220→		products,
221→		limit,
222→		blendStrategy,
223→	}: {
224→		type: RecommendationType;
225→		products: { productId: number; colorId?: number }[] | undefined;
226→		limit: number;
227→		blendStrategy: BlendStrategy;
228→	}): Promise<{
229→		recommendations: IRelatedProduct[];
230→		fallbackUsed: boolean;
231→		fallbackReason?: string;
232→		categoryIds?: number[];
233→	}> {
234→		this.logger.log('[getRecommendationsByType] Processing recommendation type', {
235→			type,
236→			productCount: products?.length ?? 0,
237→			limit,
238→			blendStrategy,
239→		});
240→		let rawResult: IEmailRecommendationRawResult;
241→
242→		switch (type) {
243→			case RecommendationType.FBT:
244→				rawResult = await this.getFBTRecommendations({ products: products ?? [] });
245→				break;
246→			case RecommendationType.SIMILAR:
247→				rawResult = await this.getSimilarRecommendations({ products: products ?? [] });
248→				break;
249→			case RecommendationType.TRENDING:
250→				rawResult = await this.getTrendingRecommendations({ products: products ?? [] });
251→				break;
252→			default:
253→				throw new BadRequestException(`Unsupported recommendation type: ${type}`);
254→		}
255→
256→		this.logger.log('[getRecommendationsByType] Blending recommendations', {
257→			type,
258→			strategy: blendStrategy,
259→		});
260→		const blendedRecommendations = this.blendRecommendations({
261→			productRecommendations: rawResult.recommendations,
262→			strategy: blendStrategy,
263→		});
264→		this.logger.log('[getRecommendationsByType] Blending complete', {
265→			blendedCount: blendedRecommendations.length,
266→		});
267→
268→		// If we don't have enough recommendations, fill with fallback
269→		if (blendedRecommendations.length < limit) {
270→			this.logger.log(
271→				'[getRecommendationsByType] Insufficient recommendations, adding fallback',
272→				{
273→					currentCount: blendedRecommendations.length,
274→					needed: limit - blendedRecommendations.length,
275→				},
276→			);
277→			const fallbackProducts = await this.getFallbackProducts({
278→				limit: limit - blendedRecommendations.length,
279→			});
280→
281→			blendedRecommendations.push(...fallbackProducts);
282→			rawResult.fallbackUsed = true;
283→			rawResult.fallbackReason = !!rawResult.fallbackReason
284→				? rawResult.fallbackReason
285→				: `Insufficient ${type} recommendations, added fallback products`;
286→		}
287→
288→		const sourceProductIds = products?.map((p) => p.productId) ?? [];
289→		const uniqueRecommendations = this.removeDuplicatesAndExcludeSource({
290→			products: blendedRecommendations,
291→			excludeIds: sourceProductIds,
292→		});
293→
294→		const recommendations = uniqueRecommendations.slice(0, limit);
295→
296→		this.logger.log('[getRecommendationsByType] Final recommendations ready', {
297→			type,
298→			finalCount: recommendations.length,
299→			fallbackUsed: rawResult.fallbackUsed,
300→		});
301→
302→		const result: {
303→			recommendations: IRelatedProduct[];
304→			fallbackUsed: boolean;
305→			fallbackReason?: string;
306→			categoryIds?: number[];
307→		} = {
308→			recommendations,
309→			fallbackUsed: rawResult.fallbackUsed,
310→		};
311→
312→		if (rawResult.fallbackReason) {
313→			result.fallbackReason = rawResult.fallbackReason;
314→		}
315→
316→		if (rawResult.categoryIds) {
317→			result.categoryIds = rawResult.categoryIds;
318→		}
319→
320→		return result;
321→	}
