490→				(p) => p.styleId,
491→			);
492→
493→			const { products, mvRecords } =
494→				await this.productHydrationService.hydrateProductsWithColors({
495→					styleIds: fallbackStyleIds,
496→				});
497→
498→			if (products.length === 0) {
499→				this.logger.error('Failed to fetch fallback products from Algolia', '', {
500→					limit,
501→				});
502→				return [];
503→			}
504→
505→			return products.map((product) => {
506→				const mvRecord = mvRecords.get(product.style_id);
507→				const colors = this.productHydrationService.convertMvColorsToProductColors({
508→					colors: mvRecord?.colors ?? null,
509→				});
510→				return assignRandomColorToProduct({ product, availableColors: colors });
511→			});
512→		} catch (error) {
