 17→	private readonly logger = new Logger(PromotionalProductsService.name);
 18→
 19→	constructor(
 20→		private readonly trendingProductsService: TrendingProductsService,
 21→		private readonly dbPromotionalProductsService: DBPromotionalProductsService,
 22→		private readonly productHydrationService: ProductHydrationService,
 23→	) {}
 24→
 25→	@LogExecution({
 26→		paramFormatter: ([{ categoryId, limit }]: [
 27→			{ categoryId?: number; limit?: number },
 28→		]) => ({
 29→			categoryId,
 30→			limit,
 31→		}),
 32→		responseFormatter: (res: PromotionalProductsResponseDto) => ({
 33→			totalCount: res.totalCount,
 34→			trendingCount: res.trendingCount,
 35→			promotionalCount: res.promotionalCount,
 36→		}),
 37→	})
 38→	async getPromotionalProducts({
 39→		categoryId,
 40→		limit = 20,
 41→	}: {
 42→		categoryId?: number | undefined;
 43→		limit?: number | undefined;
 44→	}): Promise<PromotionalProductsResponseDto> {
 45→		this.logger.log('[getPromotionalProducts] Starting promotional products fetch', {
 46→			categoryId: categoryId ?? 'random',
 47→			limit,
 48→		});
 49→
 50→		try {
 51→			const halfLimit = Math.floor(limit / 2);
 52→
 53→			const dbPromotionalProducts = categoryId
 54→				? await this.dbPromotionalProductsService.getProductsByCategory({
 55→						categoryId,
 56→						limit: halfLimit,
 57→					})
 58→				: await this.dbPromotionalProductsService.getRandomProducts(halfLimit);
 59→			this.logger.log('[getPromotionalProducts] DB promotional products fetched', {
 60→				count: dbPromotionalProducts.length,
 61→			});
 62→
 63→			const promotionalProducts: IRelatedProduct[] = [];
 64→
 65→			if (dbPromotionalProducts.length > 0) {
 66→				const styleIds = dbPromotionalProducts.map((p) => p.product_id);
 67→
 68→				try {
 69→					const { products, mvRecords } =
 70→						await this.productHydrationService.hydrateProductsWithColors({
 71→							styleIds,
 72→						});
 73→
 74→					for (const product of products) {
 75→						const mv = mvRecords.get(product.style_id);
 76→						const colors = this.productHydrationService.convertMvColorsToProductColors({
 77→							colors: mv?.colors ?? null,
 78→						});
 79→						const productWithRandomColor = assignRandomColorToProduct({
 80→							product,
 81→							availableColors: colors,
 82→						});
 83→						promotionalProducts.push(productWithRandomColor);
 84→					}
 85→
 86→					this.logger.debug('Hydrated promotional products from MV', {
 87→						hydratedCount: promotionalProducts.length,
 88→						requestedCount: dbPromotionalProducts.length,
 89→					});
 90→				} catch (error) {
 91→					this.logger.error(
 92→						`Error hydrating promotional products from MV: ${(error as Error).message}`,
 93→						(error as Error).stack,
 94→					);
 95→				}
 96→			}
 97→
 98→			const remainingLimit = limit - promotionalProducts.length;
 99→			let trendingProducts: IRelatedProduct[] = [];
100→
101→			if (remainingLimit > 0 && categoryId) {
102→				this.logger.log(
103→					'[getPromotionalProducts] Filling remaining slots with trending',
104→					{
105→						remainingLimit,
106→						categoryId,
107→					},
108→				);
109→				const trendingResult =
110→					await this.trendingProductsService.getTrendingProductsByCategory({
111→						categoryId,
112→						excludeProductIds: promotionalProducts.map((p) => p.style_id),
113→						limit: remainingLimit,
114→					});
115→				trendingProducts = trendingResult.trendingProducts;
116→				this.logger.log('[getPromotionalProducts] Trending products fetched', {
117→					trendingCount: trendingProducts.length,
118→				});
119→			}
120→
121→			const allProducts = [...trendingProducts, ...promotionalProducts];
122→			const shuffledProducts = shuffleArray({ array: allProducts });
123→
124→			return {
125→				categoryId: categoryId ?? -1,
126→				products: shuffledProducts,
127→				totalCount: shuffledProducts.length,
128→				trendingCount: trendingProducts.length,
129→				promotionalCount: promotionalProducts.length,
130→			};
131→		} catch (error) {
132→			this.logger.error(
133→				`Error fetching promotional products for category ${categoryId ?? 'all'}: ${(error as Error).message}`,
134→				(error as Error).stack,
135→			);
136→			throw error;
137→		}
138→	}
139→}
