 65→	}: {
 66→		style: MMSStyleToProcess;
 67→		allCategories: MMSAllStyleCategory[];
 68→	}): Promise<boolean> {
 69→		try {
 70→			if (!this.isProductAllowedToProcess(style)) {
 71→				this.logger.debug(`Style ${style.id} is not allowed to process.`);
 72→				await Promise.all([
 73→					this.deleteFromAlgoliaIndex({ styleId: style.id }),
 74→					this.deleteCondensedFeatures({ styleId: style.id }),
 75→				]);
 76→				return false;
 77→			}
 78→
 79→			if (!style.colors?.length) {
 80→				this.logger.debug(`Style ${style.id} has no colors, skipping processing.`);
 81→				await Promise.all([
 82→					this.deleteFromAlgoliaIndex({ styleId: style.id }),
 83→					this.deleteCondensedFeatures({ styleId: style.id }),
 84→				]);
 85→				return false;
 86→			}
 87→
 88→			const featuresRelatedFields = this.extractFeaturesRelatedFields({
 89→				style,
 90→				allCategories,
 91→			});
 92→
 93→			const isProductActive = this.checkIsProductActive({
 94→				status: style.status,
 95→				colors: style.colors,
 96→			});
 97→
 98→			await this.saveStyleToDatabase({ style, allCategories, isProductActive });
 99→
100→			const newHash = hashFromObject({
101→				obj: featuresRelatedFields as unknown as Record<string, unknown>,
102→			});
103→			const storedHash = await this.getStoredHash({ styleId: style.id });
104→
105→			const isCondensedFeaturesExists =
106→				await this.condensedFeaturesService.getCondensedFeature({
107→					styleId: style.id,
108→				});
109→
110→			if (!storedHash) {
111→				if (!isCondensedFeaturesExists) {
112→					this.logger.debug(
113→						`Style ${style.id}: no hash, no features. Creating new features`,
114→					);
115→
116→					const condensedFeatures = isProductActive
117→						? await this.generateLLMFeatures({ style, featuresRelatedFields })
118→						: [];
119→					await this.saveCondensedFeatures({ styleId: style.id, condensedFeatures });
120→					await this.createHash({ styleId: style.id, hash: newHash });
121→					await this.updateAlgoliaIndex({
122→						style,
123→						allCategories,
124→						condensedFeatures,
125→					});
126→				} else {
127→					this.logger.debug(
128→						`Style ${style.id}: no hash, but features exist. Generating hash`,
129→					);
130→					await this.createHash({ styleId: style.id, hash: newHash });
131→					await this.updateAlgoliaIndex({
132→						style,
133→						allCategories,
134→						condensedFeatures: isCondensedFeaturesExists.condensed_features,
135→					});
136→				}
137→
138→				return true;
139→			} else if (storedHash && !compareHashes({ hash1: newHash, hash2: storedHash })) {
140→				this.logger.debug(`Style ${style.id}: hash changed, updating features and index`);
141→
142→				const condensedFeatures = isProductActive
143→					? await this.generateLLMFeatures({ style, featuresRelatedFields })
144→					: (isCondensedFeaturesExists?.condensed_features ?? []);
145→				await this.updateStoredHash({ styleId: style.id, hash: newHash });
146→				await this.updateCondensedFeatures({ styleId: style.id, condensedFeatures });
147→				await this.updateAlgoliaIndex({
148→					style,
149→					allCategories,
150→					condensedFeatures,
151→				});
152→				return true;
153→			} else if (storedHash && !isCondensedFeaturesExists) {
154→				this.logger.debug(
155→					`Style ${style.id}: hash exists, but no features exist. Creating new features`,
156→				);
157→				const condensedFeatures = isProductActive
158→					? await this.generateLLMFeatures({ style, featuresRelatedFields })
159→					: [];
160→				await this.saveCondensedFeatures({ styleId: style.id, condensedFeatures });
161→				await this.updateAlgoliaIndex({
162→					style,
163→					allCategories,
164→					condensedFeatures,
165→				});
166→				return true;
167→			}
168→
169→			await this.updateAlgoliaIndex({
170→				style,
171→				allCategories,
172→				condensedFeatures: isCondensedFeaturesExists?.condensed_features ?? [],
173→			});
174→			this.logger.debug(`Style ${style.id}: hash is the same, no changes needed`);
175→			return false;
176→		} catch (error) {
177→			this.logger.error(`Error processing style ${style.id}:`, error);
178→			throw error;
179→		}
180→	}
