587→	private getBroadCategoryNames({
588→		categories,
589→		allCategories,
590→	}: {
591→		styleId?: number;
592→		categories: MMSStyleToProcess['categories'];
593→		allCategories: MMSAllStyleCategory[];
594→	}): string[] {
595→		const activeCategories = categories
596→			.map((cat) => {
597→				const fullCategory = allCategories.find((c) => c._id === cat.parent_id);
598→				if (fullCategory) {
599→					cat['parent'] = fullCategory;
600→				}
601→				return cat;
602→			})
603→			.filter((cat) => cat.active);
604→
605→		const allParents = activeCategories
606→			.map((category) => category['parent'] ?? { ...category, _id: category.id })
607→			.filter(Boolean) as MMSAllStyleCategory[];
608→
609→		const uniqueParents = allParents.reduce<MMSAllStyleCategory[]>((acc, parent) => {
610→			if (TAXONOMY_CAT_IDS.includes(parent._id)) {
611→				return acc;
612→			}
613→
614→			if (!acc.some((p) => p._id === parent._id)) {
615→				acc.push(parent);
616→			}
617→
618→			return acc;
619→		}, []);
620→
621→		const names = uniqueParents
622→			.map((parent) => parent['name'])
623→			.filter((name) => name && !EXCLUDED_CAT_NAMES.includes(name as string)) as string[];
624→
625→		return [...new Set(names)];
626→	}
