702→	private extractCategoriesWithParents({
703→		categoryIds,
704→		allCategories,
705→	}: {
706→		categoryIds: number[];
707→		allCategories: MMSAllStyleCategory[];
708→	}): number[] {
709→		const allCategoryIds = new Set<number>();
710→
711→		for (const categoryId of categoryIds) {
712→			allCategoryIds.add(categoryId);
713→
714→			const parentIds = this.getAllParentCategoryIds({ categoryId, allCategories });
715→			for (const parentId of parentIds) {
716→				allCategoryIds.add(parentId);
717→			}
718→		}
719→
720→		return Array.from(allCategoryIds).sort((a, b) => a - b);
721→	}
722→
723→	private getAllParentCategoryIds({
724→		categoryId,
725→		allCategories,
726→	}: {
727→		categoryId: number;
728→		allCategories: MMSAllStyleCategory[];
729→	}): number[] {
730→		const parents: number[] = [];
731→		const category = allCategories.find((cat) => cat._id === categoryId);
732→
733→		if (!category?.['parent_id']) {
734→			return parents;
735→		}
736→
737→		let currentParentId = category['parent_id'] as number;
738→
739→		while (currentParentId) {
740→			parents.push(currentParentId);
741→
742→			const parentCategory = allCategories.find((cat) => cat._id === currentParentId);
743→			if (!parentCategory?.['parent_id']) {
744→				break;
745→			}
746→
747→			currentParentId = parentCategory['parent_id'] as number;
748→		}
749→
750→		return parents;
751→	}
752→
753→	private getRootCategoryId({
754→		style,
755→		allCategories,
756→	}: {
757→		style: MMSStyleToProcess;
758→		allCategories: MMSAllStyleCategory[];
759→	}): number | null {
760→		if (!style.primary_category) {
761→			return null;
762→		}
763→
764→		const primaryCategory = allCategories.find(
765→			(cat) => cat._id === style.primary_category_id,
766→		);
767→		if (!primaryCategory) {
768→			return null;
769→		}
770→
771→		let currentCategory = primaryCategory;
772→		while (currentCategory['parent_id']) {
773→			const parentCategory = allCategories.find(
774→				(cat) => cat._id === currentCategory['parent_id'],
775→			);
776→			if (!parentCategory) break;
777→			currentCategory = parentCategory;
778→		}
779→
780→		return !currentCategory['parent_id'] ? currentCategory._id : null;
781→	}
782→}
