import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { CacheService, ConsistencyLevel } from '@modules/cache/cache.service';

import {
	REDIS_WRITE_CLIENT,
	REDIS_READ_CLIENT,
	CACHE_WRITE_MANAGER,
	CACHE_READ_MANAGER,
} from '@constants/common.constant';

import { Namespaces } from '@interfaces/cache.interface';

describe('CacheService', () => {
	let service: CacheService;
	let loggerLogSpy: jest.SpyInstance;
	let loggerErrorSpy: jest.SpyInstance;

	const mockNamespace = Namespaces.RELATED_ITEMS_MODEL;
	const mockKey = 'test-key';
	const mockNamespacedKey = `${mockNamespace}:${mockKey}`;
	const mockValue = { data: 'test-value' };
	const mockTtl = 3600;
	const mockError = new Error('Cache error');

	const mockCacheWriteManager = {
		get: jest.fn(),
		set: jest.fn(),
		delete: jest.fn(),
		clear: jest.fn(),
	};

	const mockCacheReadManager = {
		get: jest.fn(),
		set: jest.fn(),
		delete: jest.fn(),
		clear: jest.fn(),
	};

	const mockRedisWriteClient = {
		get: jest.fn(),
		set: jest.fn(),
		setex: jest.fn(),
		del: jest.fn(),
		eval: jest.fn(),
		incr: jest.fn(),
		on: jest.fn(),
		multi: jest.fn(() => ({
			get: jest.fn(),
			set: jest.fn(),
			del: jest.fn(),
			exec: jest.fn(),
		})),
	};

	const mockRedisReadClient = {
		get: jest.fn(),
		set: jest.fn(),
		del: jest.fn(),
		eval: jest.fn(),
		on: jest.fn(),
		multi: jest.fn(() => ({
			get: jest.fn(),
			set: jest.fn(),
			del: jest.fn(),
			exec: jest.fn(),
		})),
	};

	beforeEach(async () => {
		jest.clearAllMocks();
		jest.useFakeTimers();

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				CacheService,
				{
					provide: CACHE_WRITE_MANAGER,
					useValue: mockCacheWriteManager,
				},
				{
					provide: CACHE_READ_MANAGER,
					useValue: mockCacheReadManager,
				},
				{
					provide: REDIS_WRITE_CLIENT,
					useValue: mockRedisWriteClient,
				},
				{
					provide: REDIS_READ_CLIENT,
					useValue: mockRedisReadClient,
				},
			],
		}).compile();

		service = module.get<CacheService>(CacheService);

		loggerLogSpy = jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		loggerErrorSpy = jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'debug').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
	});

	afterEach(() => {
		jest.resetAllMocks();
		jest.useRealTimers();
	});

	it('should be defined', () => {
		expect(service).toBeDefined();
	});

	describe('get', () => {
		it('should return cached value on cache hit', async () => {
			mockCacheReadManager.get.mockResolvedValueOnce(mockValue);

			const result = await service.get({
				namespace: mockNamespace,
				key: mockKey,
			});

			expect(mockCacheReadManager.get).toHaveBeenCalledWith(mockNamespacedKey);
			expect(result).toEqual(mockValue);
			expect(loggerLogSpy).toHaveBeenCalledWith('Cache hit', {
				namespace: mockNamespace,
				key: mockKey,
			});
		});

		it('should return null on cache miss', async () => {
			mockCacheReadManager.get.mockResolvedValueOnce(null);

			const result = await service.get({
				namespace: mockNamespace,
				key: mockKey,
			});

			expect(mockCacheReadManager.get).toHaveBeenCalledWith(mockNamespacedKey);
			expect(result).toBeNull();
		});

		it('should handle errors and return null', async () => {
			mockCacheReadManager.get.mockRejectedValueOnce(mockError);

			const result = await service.get({
				namespace: mockNamespace,
				key: mockKey,
			});

			expect(mockCacheReadManager.get).toHaveBeenCalledWith(mockNamespacedKey);
			expect(result).toBeNull();
			expect(loggerErrorSpy).toHaveBeenCalledWith(
				`Error retrieving from cache: ${mockError.message}`,
				mockError.stack,
				expect.objectContaining({ source: 'replica' }),
			);
		});
	});

	describe('set', () => {
		it('should successfully set a value in cache', async () => {
			mockCacheWriteManager.set.mockResolvedValueOnce(undefined);

			await service.set({
				namespace: mockNamespace,
				key: mockKey,
				value: mockValue,
				ttl: mockTtl,
			});

			expect(mockCacheWriteManager.set).toHaveBeenCalledWith(
				mockNamespacedKey,
				mockValue,
				mockTtl,
			);
			expect(loggerLogSpy).toHaveBeenCalledWith('Cached value', {
				namespace: mockNamespace,
				key: mockKey,
				ttl: mockTtl,
			});
		});

		it('should set a value without TTL', async () => {
			mockCacheWriteManager.set.mockResolvedValueOnce(undefined);

			await service.set({
				namespace: mockNamespace,
				key: mockKey,
				value: mockValue,
			});

			expect(mockCacheWriteManager.set).toHaveBeenCalledWith(
				mockNamespacedKey,
				mockValue,
				undefined,
			);
		});

		it('should throw error when setting cache fails', async () => {
			mockCacheWriteManager.set.mockRejectedValueOnce(mockError);

			await expect(
				service.set({
					namespace: mockNamespace,
					key: mockKey,
					value: mockValue,
				}),
			).rejects.toThrow('Cache operation failed: OPERATION_FAILED');

			expect(loggerErrorSpy).toHaveBeenCalledWith(
				`Error setting cache: ${mockError.message}`,
				mockError.stack,
			);
		});
	});

	describe('has', () => {
		it('should return true when key exists', async () => {
			mockCacheReadManager.get.mockResolvedValueOnce(mockValue);

			const result = await service.has({
				namespace: mockNamespace,
				key: mockKey,
			});

			expect(mockCacheReadManager.get).toHaveBeenCalledWith(mockNamespacedKey);
			expect(result).toBe(true);
		});

		it('should return false when key does not exist', async () => {
			mockCacheReadManager.get.mockResolvedValueOnce(null);

			const result = await service.has({
				namespace: mockNamespace,
				key: mockKey,
			});

			expect(mockCacheReadManager.get).toHaveBeenCalledWith(mockNamespacedKey);
			expect(result).toBe(false);
		});
	});

	describe('deleteOne', () => {
		it('should successfully delete a cache entry', async () => {
			mockCacheWriteManager.delete.mockResolvedValueOnce(undefined);

			const result = await service.deleteOne({
				namespace: mockNamespace,
				key: mockKey,
			});

			expect(mockCacheWriteManager.delete).toHaveBeenCalledWith(mockNamespacedKey);
			expect(result).toBe(true);
			expect(loggerLogSpy).toHaveBeenCalledWith('Deleted cache key', {
				namespace: mockNamespace,
				key: mockKey,
			});
		});

		it('should handle errors when deleting a cache entry', async () => {
			mockCacheWriteManager.delete.mockRejectedValueOnce(mockError);

			const result = await service.deleteOne({
				namespace: mockNamespace,
				key: mockKey,
			});

			expect(mockCacheWriteManager.delete).toHaveBeenCalledWith(mockNamespacedKey);
			expect(result).toBe(false);
			expect(loggerErrorSpy).toHaveBeenCalledWith(
				`Error deleting from cache: ${mockError.message}`,
				mockError.stack,
			);
		});
	});

	describe('deleteAll', () => {
		it('should successfully clear all cache entries', async () => {
			mockCacheWriteManager.clear.mockResolvedValueOnce(undefined);
			mockCacheReadManager.clear.mockResolvedValueOnce(undefined);

			const deleteAllPromise = service.deleteAll();

			await jest.advanceTimersByTimeAsync(100);

			const result = await deleteAllPromise;

			expect(mockCacheWriteManager.clear).toHaveBeenCalled();
			expect(mockCacheReadManager.clear).toHaveBeenCalled();
			expect(result).toBe(true);
			expect(loggerLogSpy).toHaveBeenCalledWith('Cleared all cache');
		});

		it('should handle errors when clearing all cache entries', async () => {
			mockCacheWriteManager.clear.mockRejectedValueOnce(mockError);

			const result = await service.deleteAll();

			expect(mockCacheWriteManager.clear).toHaveBeenCalled();
			expect(result).toBe(false);
			expect(loggerErrorSpy).toHaveBeenCalledWith(
				`Error clearing cache: ${mockError.message}`,
				mockError.stack,
			);
		});
	});

	describe('incrementByOne', () => {
		it('should successfully increment a cache value', async () => {
			mockRedisWriteClient.incr.mockResolvedValueOnce(1);

			await service.incrementByOne({
				namespace: mockNamespace,
				key: mockKey,
			});

			expect(mockRedisWriteClient.incr).toHaveBeenCalledWith(mockNamespacedKey);
		});

		it('should handle errors when incrementing cache value', async () => {
			mockRedisWriteClient.incr.mockRejectedValueOnce(mockError);

			await expect(
				service.incrementByOne({
					namespace: mockNamespace,
					key: mockKey,
				}),
			).rejects.toThrow(mockError);

			expect(loggerErrorSpy).toHaveBeenCalledWith(
				`Error incrementing cache key: ${mockError.message}`,
				mockError.stack,
				expect.objectContaining({ namespace: mockNamespace, key: mockKey }),
			);
		});
	});

	describe('withLock', () => {
		const mockLockKey = 'test-lock-key';
		const mockTtl = 5000;
		const mockOperation = jest.fn();
		const mockLock = {
			release: jest.fn(),
		};

		beforeEach(() => {
			Object.defineProperty(service, 'redlock', {
				value: {
					acquire: jest.fn().mockResolvedValue(mockLock),
				},
				writable: true,
			});
		});

		it('should acquire lock, execute operation, and release lock', async () => {
			const expectedResult = 'operation-result';
			mockOperation.mockResolvedValueOnce(expectedResult);

			const result = await service.withLock({
				lockKey: mockLockKey,
				operation: mockOperation,
				ttl: mockTtl,
			});

			expect(result).toBe(expectedResult);
			expect(mockOperation).toHaveBeenCalled();
			expect(mockLock.release).toHaveBeenCalled();
		});

		it('should release lock even if operation throws error', async () => {
			const operationError = new Error('Operation failed');
			mockOperation.mockRejectedValueOnce(operationError);

			await expect(
				service.withLock({
					lockKey: mockLockKey,
					operation: mockOperation,
				}),
			).rejects.toThrow(operationError);

			expect(mockLock.release).toHaveBeenCalled();
		});
	});

	describe('acquireLock', () => {
		const mockLockKey = 'test-lock-key';
		const mockTtl = 5000;
		const mockLock = {
			release: jest.fn(),
		};

		beforeEach(() => {
			Object.defineProperty(service, 'redlock', {
				value: {
					acquire: jest.fn().mockResolvedValue(mockLock),
				},
				writable: true,
			});
		});

		it('should successfully acquire a lock', async () => {
			const result = await service.acquireLock({
				lockKey: mockLockKey,
				ttl: mockTtl,
			});

			expect(result).toBe(mockLock);
			expect(loggerLogSpy).toHaveBeenCalledWith('Acquiring lock', {
				lockKey: mockLockKey,
				ttlMs: mockTtl,
			});
		});

		it('should handle errors when acquiring lock', async () => {
			const lockError = new Error('Lock acquisition failed');
			Object.defineProperty(service, 'redlock', {
				value: {
					acquire: jest.fn().mockRejectedValue(lockError),
				},
				writable: true,
			});

			await expect(
				service.acquireLock({
					lockKey: mockLockKey,
					ttl: mockTtl,
				}),
			).rejects.toThrow(lockError);

			expect(loggerErrorSpy).toHaveBeenCalledWith(`Failed to acquire lock: ${lockError}`);
		});
	});

	describe('releaseLock', () => {
		const mockLock = {
			release: jest.fn(),
			resources: ['test-lock-key'],

			redlock: {} as any,
			value: 'test-value',

			attempts: [] as any,
			expiration: Date.now() + 5000,
			extend: jest.fn(),
		};

		it('should successfully release a lock', async () => {
			mockLock.release.mockResolvedValueOnce(undefined);

			await service.releaseLock({ lock: mockLock });

			expect(mockLock.release).toHaveBeenCalled();
			expect(loggerLogSpy).toHaveBeenCalledWith('Releasing lock', {
				lockKey: mockLock.resources[0],
			});
		});

		it('should handle errors when releasing lock', async () => {
			const releaseError = new Error('Lock release failed');
			mockLock.release.mockRejectedValueOnce(releaseError);

			await expect(service.releaseLock({ lock: mockLock })).rejects.toThrow(releaseError);

			expect(loggerErrorSpy).toHaveBeenCalledWith(
				`Failed to release lock: ${releaseError}`,
			);
		});
	});

	describe('consistency levels', () => {
		it('should read from write manager when using strong consistency', async () => {
			mockCacheWriteManager.get.mockResolvedValueOnce(mockValue);

			const result = await service.get({
				namespace: mockNamespace,
				key: mockKey,
				consistency: ConsistencyLevel.STRONG,
			});

			expect(mockCacheWriteManager.get).toHaveBeenCalledWith(mockNamespacedKey);
			expect(mockCacheReadManager.get).not.toHaveBeenCalled();
			expect(result).toEqual(mockValue);
		});

		it('should read from read manager when using eventual consistency', async () => {
			mockCacheReadManager.get.mockResolvedValueOnce(mockValue);

			const result = await service.get({
				namespace: mockNamespace,
				key: mockKey,
				consistency: ConsistencyLevel.EVENTUAL,
			});

			expect(mockCacheReadManager.get).toHaveBeenCalledWith(mockNamespacedKey);
			expect(mockCacheWriteManager.get).not.toHaveBeenCalled();
			expect(result).toEqual(mockValue);
		});

		it('should fallback to master when read replica fails and is healthy', async () => {
			mockCacheReadManager.get.mockRejectedValueOnce(mockError);
			mockCacheWriteManager.get.mockResolvedValueOnce(mockValue);

			const result = await service.get({
				namespace: mockNamespace,
				key: mockKey,
				consistency: ConsistencyLevel.EVENTUAL,
			});

			expect(mockCacheReadManager.get).toHaveBeenCalledWith(mockNamespacedKey);
			expect(mockCacheWriteManager.get).toHaveBeenCalledWith(mockNamespacedKey);
			expect(result).toEqual(mockValue);
		});

		it('should read from master when replica is unhealthy', async () => {
			const errorHandler = mockRedisReadClient.on.mock.calls.find(
				(call: [string, ...unknown[]]) => call[0] === 'error',
			)?.[1] as ((error: Error) => void) | undefined;
			if (errorHandler) {
				errorHandler(new Error('Connection failed'));
			}

			mockCacheWriteManager.get.mockResolvedValueOnce(mockValue);

			const result = await service.get({
				namespace: mockNamespace,
				key: mockKey,
				consistency: ConsistencyLevel.EVENTUAL,
			});

			expect(mockCacheWriteManager.get).toHaveBeenCalledWith(mockNamespacedKey);
			expect(mockCacheReadManager.get).not.toHaveBeenCalled();
			expect(result).toEqual(mockValue);
