		});

		it('should log write client errors', () => {
			const errorHandler = mockRedisWriteClient.on.mock.calls.find(
				(call: [string, ...unknown[]]) => call[0] === 'error',
			)?.[1] as ((error: Error) => void) | undefined;

			if (errorHandler) {
				const error = new Error('Write client error');
				errorHandler(error);
			}

			expect(loggerErrorSpy).toHaveBeenCalledWith(
				'Write client connection error:',
				expect.any(Error),
			);
		});
	});

	describe('recent writes cleanup', () => {
		it('should clean up old entries from recentWrites map', async () => {
			mockCacheWriteManager.set.mockResolvedValueOnce(undefined);
			await service.set({
				namespace: mockNamespace,
				key: mockKey,
				value: mockValue,
			});

			jest.advanceTimersByTime(3000);

			mockCacheReadManager.get.mockResolvedValueOnce(mockValue);

			await service.get({
				namespace: mockNamespace,
				key: mockKey,
				consistency: ConsistencyLevel.EVENTUAL,
			});

			expect(mockCacheReadManager.get).toHaveBeenCalled();
			expect(mockCacheWriteManager.get).not.toHaveBeenCalled();
		});
	});

	describe('error handling', () => {
		it('should throw CONNECTION_FAILED error when master fails after replica fallback attempt', async () => {
			const errorHandler = mockRedisReadClient.on.mock.calls.find(
				(call: [string, ...unknown[]]) => call[0] === 'error',
			)?.[1] as ((error: Error) => void) | undefined;
			if (errorHandler) {
				errorHandler(new Error('Connection failed'));
			}

