		});

		it('should throw CONNECTION_FAILED error when replica fails and is already unhealthy', async () => {
			const errorHandler = mockRedisReadClient.on.mock.calls.find(
				(call: [string, ...unknown[]]) => call[0] === 'error',
			)?.[1] as ((error: Error) => void) | undefined;
			if (errorHandler) {
				errorHandler(new Error('Connection failed'));
			}
			mockCacheWriteManager.get.mockRejectedValueOnce(mockError);

			await expect(
				service.get({
					namespace: mockNamespace,
					key: mockKey,
					consistency: ConsistencyLevel.EVENTUAL,
				}),
			).rejects.toThrow('Cache operation failed: CONNECTION_FAILED');
		});

		it('should create cache error with original error', async () => {
			mockCacheWriteManager.set.mockRejectedValueOnce(mockError);

			try {
				await service.set({
					namespace: mockNamespace,
					key: mockKey,
					value: mockValue,
				});
			} catch (error) {
				expect(error).toHaveProperty('code', 'OPERATION_FAILED');
				expect(error).toHaveProperty('originalError', mockError);
			}
		});

		it('should create cache error without original error', () => {
			const createCacheError = (service as any).createCacheError.bind(service);

			const error = createCacheError({ code: 'KEY_NOT_FOUND' });

			expect(error).toHaveProperty('code', 'KEY_NOT_FOUND');
			expect(error).toHaveProperty('message', 'Cache operation failed: KEY_NOT_FOUND');

			expect(error.originalError).toBeUndefined();
		});
	});
});

