import { Injectable, Logger, BadRequestException } from '@nestjs/common';

import { StyleColorsService } from '@modules/db/style-colors/style-colors.service';
import { StylesService } from '@modules/db/styles/styles.service';
import { ProductHydrationService } from '@modules/product-hydration/product-hydration.service';
import { FrequentlyBoughtTogetherService } from '@modules/rest/frequently-bought-together/frequently-bought-together.service';
import { RelatedProductsService } from '@modules/rest/related-products/related-products.service';
import { TrendingProductsService } from '@modules/rest/trending-products/trending-products.service';

import { assignRandomColorToProduct } from '@utils/random-color-picker.util';

import { IRelatedProduct } from '@interfaces/related-product.interface';

import { LogExecution } from '@decorators/log-execution.decorator';

import {
	EmailRecommendationsQueryDto,
	RecommendationType,
	BlendStrategy,
} from '@dto/email-recommendations/email-recommendations-query.dto';
import { EmailRecommendationsResponseDto } from '@dto/email-recommendations/email-recommendations-response.dto';

interface IEmailRecommendationRawResult {
	recommendations: Map<number, IRelatedProduct[]>;
	fallbackUsed: boolean;
	fallbackReason?: string;
	categoryIds?: number[];
}
const DEFAULT_LIMIT_FOR_EMAILS_RECOMMENDATIONS = 6;
@Injectable()
export class EmailRecommendationsService {
	private readonly logger = new Logger(EmailRecommendationsService.name);

	// TODO: Fallback products for edge cases, need to take from merchandise team
	private readonly FALLBACK_PRODUCTS = [
		{ styleId: 176100, name: 'Gildan Softstyle Jersey T-shirt' },
		{ styleId: 1000200, name: 'The North Face Stalwart 15" Computer Backpack' },
		{ styleId: 378400, name: '22 oz. Thor Copper Vacuum Insulated Water Bottle' },
		{ styleId: 349500, name: 'Medium Hard Cover Notebook' },
	];

	constructor(
		private readonly frequentlyBoughtTogetherService: FrequentlyBoughtTogetherService,
		private readonly productHydrationService: ProductHydrationService,
		private readonly relatedProductsService: RelatedProductsService,
		private readonly trendingProductsService: TrendingProductsService,
		private readonly stylesService: StylesService,
		private readonly styleColorsService: StyleColorsService,
	) {}

	private async resolveProductIds({
		products,
	}: {
		products: { productId?: number; colorId?: number }[] | undefined;
	}): Promise<{ productId: number; colorId?: number }[]> {
		if (!products || products.length === 0) {
			this.logger.log('[resolveProductIds] No products to resolve', { products });
			return [];
		}

		this.logger.log('[resolveProductIds] Starting resolution', {
			inputCount: products.length,
		});
		const resolvedProducts: { productId: number; colorId?: number }[] = [];

		for (const product of products) {
			if (product.productId) {
				const resolvedProduct: { productId: number; colorId?: number } = {
					productId: product.productId,
				};
				if (product.colorId) {
					resolvedProduct.colorId = product.colorId;
				}
				resolvedProducts.push(resolvedProduct);
			} else if (product.colorId) {
				try {
					const styleColor = await this.styleColorsService.getStyleByColorId({
						colorId: product.colorId,
					});

					if (!styleColor) {
						this.logger.warn('Could not find style for colorId', {
							colorId: product.colorId,
						});
						continue;
					}

					const productId = Number(styleColor.style_id);
					if (isNaN(productId)) {
						this.logger.warn('Invalid style_id for colorId', {
							styleId: styleColor.style_id,
							colorId: product.colorId,
						});
						continue;
					}

					resolvedProducts.push({
						productId,
						colorId: product.colorId,
					});
				} catch (error) {
					this.logger.warn(
						`Error resolving productId from colorId ${product.colorId}: ${error}`,
					);
				}
			}
		}

		return resolvedProducts;
	}

	@LogExecution({
		paramFormatter: ([{ query }]: [{ query: EmailRecommendationsQueryDto }]) => ({
			types: query.types,
			productCount: query.products?.length ?? 0,
			limit: query.limit,
			blendStrategy: query.blendStrategy,
		}),
		responseFormatter: (res: EmailRecommendationsResponseDto) => ({
			fbtCount: res.fbt_products?.length ?? 0,
			similarCount: res.similar_products?.length ?? 0,
			trendingCount: res.trending_products?.length ?? 0,
			fallbackUsed: res.fallback_used ?? false,
		}),
	})
	async getEmailRecommendations({
		query,
	}: {
		query: EmailRecommendationsQueryDto;
	}): Promise<EmailRecommendationsResponseDto> {
		const {
			types,
			products,
			limit = DEFAULT_LIMIT_FOR_EMAILS_RECOMMENDATIONS,
			blendStrategy = BlendStrategy.RATING,
		} = query;

		const resolvedProducts = await this.resolveProductIds({ products });

		// Default to all types if none specified
		const requestedTypes =
			types && types.length > 0
				? types
				: [
						RecommendationType.FBT,
						RecommendationType.SIMILAR,
						RecommendationType.TRENDING,
					];

		this.logger.log('Getting email recommendations', {
			types: requestedTypes,
			productCount: resolvedProducts.length,
			limit,
		});

		try {
			const response: EmailRecommendationsResponseDto = {};
			const fallbackReasons: Record<string, string> = {};
			let anyFallbackUsed = false;
			let categoryIds: number[] = [];

			for (const type of requestedTypes) {
				if (!Object.values(RecommendationType).includes(type)) {
					this.logger.warn('Unsupported recommendation type', { type });
					continue;
				}

				const result = await this.getRecommendationsByType({
					type,
					products: resolvedProducts,
					limit,
					blendStrategy,
				});

				switch (type) {
					case RecommendationType.FBT:
						response.fbt_products = result.recommendations;
						break;
					case RecommendationType.SIMILAR:
						response.similar_products = result.recommendations;
						break;
					case RecommendationType.TRENDING:
						response.trending_products = result.recommendations;
						break;
				}

				if (result.fallbackUsed && result.fallbackReason) {
					anyFallbackUsed = true;
					fallbackReasons[type] = result.fallbackReason;
				}

				if (result.categoryIds && result.categoryIds.length > 0) {
					categoryIds = result.categoryIds;
				}
			}

			if (resolvedProducts.length > 0) {
				response.source_product_ids = resolvedProducts.map((p) => p.productId);
			}
			if (categoryIds.length > 0) {
				response.category_ids = categoryIds;
			}
			if (anyFallbackUsed) {
				response.fallback_used = true;
				response.fallback_reasons = fallbackReasons;
			}

			return response;
		} catch (error) {
			this.logger.error(
				`Error getting email recommendations: ${(error as Error).message}`,
				(error as Error).stack,
			);
			throw error;
		}
	}

	private async getRecommendationsByType({
		type,
		products,
		limit,
		blendStrategy,
	}: {
		type: RecommendationType;
		products: { productId: number; colorId?: number }[] | undefined;
		limit: number;
		blendStrategy: BlendStrategy;
	}): Promise<{
		recommendations: IRelatedProduct[];
		fallbackUsed: boolean;
		fallbackReason?: string;
		categoryIds?: number[];
	}> {
		this.logger.log('[getRecommendationsByType] Processing recommendation type', {
			type,
			productCount: products?.length ?? 0,
			limit,
			blendStrategy,
		});
		let rawResult: IEmailRecommendationRawResult;

		switch (type) {
			case RecommendationType.FBT:
				rawResult = await this.getFBTRecommendations({ products: products ?? [] });
				break;
			case RecommendationType.SIMILAR:
				rawResult = await this.getSimilarRecommendations({ products: products ?? [] });
				break;
			case RecommendationType.TRENDING:
				rawResult = await this.getTrendingRecommendations({ products: products ?? [] });
				break;
			default:
				throw new BadRequestException(`Unsupported recommendation type: ${type}`);
		}

		this.logger.log('[getRecommendationsByType] Blending recommendations', {
			type,
			strategy: blendStrategy,
		});
		const blendedRecommendations = this.blendRecommendations({
			productRecommendations: rawResult.recommendations,
			strategy: blendStrategy,
		});
		this.logger.log('[getRecommendationsByType] Blending complete', {
			blendedCount: blendedRecommendations.length,
		});

		// If we don't have enough recommendations, fill with fallback
		if (blendedRecommendations.length < limit) {
			this.logger.log(
				'[getRecommendationsByType] Insufficient recommendations, adding fallback',
				{
					currentCount: blendedRecommendations.length,
					needed: limit - blendedRecommendations.length,
				},
			);
			const fallbackProducts = await this.getFallbackProducts({
				limit: limit - blendedRecommendations.length,
			});

			blendedRecommendations.push(...fallbackProducts);
			rawResult.fallbackUsed = true;
			rawResult.fallbackReason = !!rawResult.fallbackReason
				? rawResult.fallbackReason
				: `Insufficient ${type} recommendations, added fallback products`;
		}

		const sourceProductIds = products?.map((p) => p.productId) ?? [];
		const uniqueRecommendations = this.removeDuplicatesAndExcludeSource({
			products: blendedRecommendations,
			excludeIds: sourceProductIds,
		});

		const recommendations = uniqueRecommendations.slice(0, limit);

		this.logger.log('[getRecommendationsByType] Final recommendations ready', {
			type,
			finalCount: recommendations.length,
			fallbackUsed: rawResult.fallbackUsed,
		});

		const result: {
			recommendations: IRelatedProduct[];
			fallbackUsed: boolean;
			fallbackReason?: string;
			categoryIds?: number[];
		} = {
			recommendations,
			fallbackUsed: rawResult.fallbackUsed,
		};

		if (rawResult.fallbackReason) {
			result.fallbackReason = rawResult.fallbackReason;
		}

		if (rawResult.categoryIds) {
			result.categoryIds = rawResult.categoryIds;
		}

		return result;
	}

	private async getFBTRecommendations({
		products,
	}: {
		products?: { productId: number; colorId?: number }[];
	}): Promise<IEmailRecommendationRawResult> {
		if (!products?.[0] || products.length === 0) {
			throw new BadRequestException('Products are required for FBT recommendations');
		}

		this.logger.log('[getFBTRecommendations] Starting FBT fetch', {
			productIds: products.map((p) => p.productId),
		});

		const productRecommendations = new Map<number, IRelatedProduct[]>();
		let fallbackUsed = false;
		let fallbackReason = '';
		const excludeIds = products.map((p) => p.productId);

		try {
			const fbtResult =
				await this.frequentlyBoughtTogetherService.getFrequentlyBoughtTogether({
					query: {
						styleIds: products.map((p) => p.productId),
						exclude: excludeIds,
					},
				});

			products.forEach((product) => {
				productRecommendations.set(
					product.productId,
					fbtResult.frequently_bought_together,
				);
			});

			if (fbtResult.fallback_used) {
				fallbackUsed = true;
				fallbackReason = 'FBT service used fallback data';
			}
		} catch (error) {
			this.logger.warn(`FBT failed: ${error}`, {
				productIds: products.map((p) => p.productId),
			});
			products.forEach((product) => {
				productRecommendations.set(product.productId, []);
			});
			fallbackUsed = true;
			fallbackReason = 'FBT service failed';
		}

		return {
			recommendations: productRecommendations,
			fallbackUsed,
			fallbackReason,
		};
	}

	private async getSimilarRecommendations({
		products,
	}: {
		products?: { productId: number; colorId?: number }[];
	}): Promise<IEmailRecommendationRawResult> {
		if (!products || products.length === 0) {
			throw new BadRequestException('Products are required for Similar recommendations');
		}

		this.logger.log('[getSimilarRecommendations] Starting similar fetch', {
			productIds: products.map((p) => p.productId),
		});

		const productRecommendations = new Map<number, IRelatedProduct[]>();
		let fallbackUsed = false;
		let fallbackReason = '';

		for (const product of products) {
			try {
				const similarResult = await this.relatedProductsService.getRelatedProducts(
					product.productId.toString(),
					{ ...(product.colorId && { colorId: product.colorId }) },
				);

				productRecommendations.set(product.productId, similarResult.related_products);

				if (similarResult.mms_fallback && !fallbackUsed) {
					fallbackUsed = true;
					fallbackReason = 'Related products service used MMS fallback';
				}
			} catch (error) {
				this.logger.warn(`Similar recommendations failed: ${error}`, {
					productId: product.productId,
					colorId: product.colorId,
				});
				productRecommendations.set(product.productId, []);
				fallbackUsed = true;
				fallbackReason = 'Similar recommendations failed';
			}
		}

		return {
			recommendations: productRecommendations,
			fallbackUsed,
			fallbackReason,
		};
	}

	private async getTrendingRecommendations({
		products,
	}: {
		products?: { productId: number; colorId?: number }[];
	}): Promise<IEmailRecommendationRawResult> {
		if (!products?.[0] || products.length === 0) {
			throw new BadRequestException('Products are required for trending recommendations');
		}

		this.logger.log('[getTrendingRecommendations] Starting trending fetch', {
			productIds: products.map((p) => p.productId),
		});

		const productRecommendations = new Map<number, IRelatedProduct[]>();
		let fallbackUsed = false;
		let fallbackReason = '';
		const sourceProductIds = products.map((p) => p.productId);

		const styles = await this.stylesService.getStylesByIds({
			styleIds: sourceProductIds,
		});

		const categoryIds = styles
			.map((style) => style.primary_category_id)
			.filter((id): id is number => id !== null);

		this.logger.log('[getTrendingRecommendations] Resolved categories from styles', {
			categoryIds,
		});

		for (const categoryId of categoryIds) {
			try {
				const trendingResult =
					await this.trendingProductsService.getTrendingProductsByCategory({
						categoryId,
						excludeProductIds: sourceProductIds,
					});

				productRecommendations.set(categoryId, trendingResult.trendingProducts);
			} catch (error) {
				this.logger.warn(`Trending recommendations failed: ${error}`, {
					categoryId,
				});
				fallbackUsed = true;
				fallbackReason = 'Trending recommendations failed';
			}
		}

		return {
			recommendations: productRecommendations,
			fallbackUsed,
			fallbackReason,
			categoryIds: categoryIds,
		};
	}

	private async getFallbackProducts({
		limit,
	}: {
		limit: number;
	}): Promise<IRelatedProduct[]> {
		this.logger.log('[getFallbackProducts] Fetching fallback products', { limit });

		try {
			const fallbackStyleIds = this.FALLBACK_PRODUCTS.slice(0, limit).map(
				(p) => p.styleId,
			);

			const { products, mvRecords } =
				await this.productHydrationService.hydrateProductsWithColors({
					styleIds: fallbackStyleIds,
				});

			if (products.length === 0) {
				this.logger.error('Failed to fetch fallback products from Algolia', '', {
					limit,
				});
				return [];
			}

			return products.map((product) => {
				const mvRecord = mvRecords.get(product.style_id);
				const colors = this.productHydrationService.convertMvColorsToProductColors({
					colors: mvRecord?.colors ?? null,
				});
				return assignRandomColorToProduct({ product, availableColors: colors });
			});
		} catch (error) {
			this.logger.error(
				`Error fetching fallback products: ${(error as Error).message}`,
				(error as Error).stack,
			);
			return [];
		}
	}

	private removeDuplicatesAndExcludeSource({
		products,
		excludeIds,
	}: {
		products: IRelatedProduct[];
		excludeIds: number[];
	}): IRelatedProduct[] {
		const seen = new Set<number>();
		return products.filter((product) => {
			if (seen.has(product.style_id)) {
				return false;
			}
			seen.add(product.style_id);
			return !excludeIds.includes(product.style_id);
		});
	}

	private blendRecommendationsRoundRobin({
		productRecommendations,
	}: {
		productRecommendations: Map<number, IRelatedProduct[]>;
	}): IRelatedProduct[] {
		const blended: IRelatedProduct[] = [];
		const productIds = Array.from(productRecommendations.keys());

		const maxLength = Math.max(
			...Array.from(productRecommendations.values()).map((arr) => arr.length),
		);

		for (let i = 0; i < maxLength; i++) {
			for (const productId of productIds) {
				const recommendations = productRecommendations.get(productId);
				if (recommendations && i < recommendations.length) {
					const rec = recommendations[i];
					if (rec) {
						if (!blended.some((el) => el.style_id === rec.style_id)) {
							blended.push(rec);
						}
					}
				}
			}
		}

		return blended;
	}

	private blendRecommendationsByRating({
		productRecommendations,
	}: {
		productRecommendations: Map<number, IRelatedProduct[]>;
	}): IRelatedProduct[] {
		const allRecommendations: IRelatedProduct[] = [];
		const seen = new Set<number>();

		for (const recommendations of productRecommendations.values()) {
			for (const rec of recommendations) {
				if (!seen.has(rec.style_id)) {
					seen.add(rec.style_id);
					allRecommendations.push(rec);
				}
			}
		}

		return allRecommendations.sort((a, b) => {
			const ratingA =
				typeof a.rating_score === 'string'
					? parseFloat(a.rating_score) || 0
					: a.rating_score || 0;
			const ratingB =
				typeof b.rating_score === 'string'
					? parseFloat(b.rating_score) || 0
					: b.rating_score || 0;

			return ratingB - ratingA;
		});
	}

	private blendRecommendations({
		productRecommendations,
		strategy,
	}: {
		productRecommendations: Map<number, IRelatedProduct[]>;
		strategy: BlendStrategy;
	}): IRelatedProduct[] {
		switch (strategy) {
			case BlendStrategy.RATING:
				return this.blendRecommendationsByRating({ productRecommendations });
			case BlendStrategy.ROUND_ROBIN:
			default:
				return this.blendRecommendationsRoundRobin({ productRecommendations });
		}
	}
}

