			expect(result).toEqual(mockValue);
		});

		it('should read from master for recently written keys', async () => {
			mockCacheWriteManager.set.mockResolvedValueOnce(undefined);
			await service.set({
				namespace: mockNamespace,
				key: mockKey,
				value: mockValue,
			});

			mockCacheWriteManager.get.mockResolvedValueOnce(mockValue);

			const result = await service.get({
				namespace: mockNamespace,
				key: mockKey,
				consistency: ConsistencyLevel.EVENTUAL,
			});

			expect(mockCacheWriteManager.get).toHaveBeenCalledWith(mockNamespacedKey);
			expect(mockCacheReadManager.get).not.toHaveBeenCalled();
			expect(result).toEqual(mockValue);
		});

		it('should read from replica after consistency window expires', async () => {
			mockCacheWriteManager.set.mockResolvedValueOnce(undefined);
			await service.set({
				namespace: mockNamespace,
				key: mockKey,
				value: mockValue,
			});

			jest.advanceTimersByTime(2000);

			mockCacheReadManager.get.mockResolvedValueOnce(mockValue);

			const result = await service.get({
				namespace: mockNamespace,
				key: mockKey,
				consistency: ConsistencyLevel.EVENTUAL,
			});

			expect(mockCacheReadManager.get).toHaveBeenCalledWith(mockNamespacedKey);
			expect(mockCacheWriteManager.get).not.toHaveBeenCalled();
			expect(result).toEqual(mockValue);
		});
	});

	describe('health checks and event handlers', () => {
		it('should mark read replica as unhealthy on error', async () => {
			const errorHandler = mockRedisReadClient.on.mock.calls.find(
				(call: [string, ...unknown[]]) => call[0] === 'error',
			)?.[1] as ((error: Error) => void) | undefined;

			if (errorHandler) {
				errorHandler(new Error('Connection failed'));
			}

			mockCacheWriteManager.get.mockResolvedValueOnce(mockValue);

			await service.get({
				namespace: mockNamespace,
				key: mockKey,
				consistency: ConsistencyLevel.EVENTUAL,
			});

			expect(mockCacheWriteManager.get).toHaveBeenCalled();
		});

		it('should mark read replica as healthy on ready event', async () => {
			const errorHandler = mockRedisReadClient.on.mock.calls.find(
				(call: [string, ...unknown[]]) => call[0] === 'error',
			)?.[1] as ((error: Error) => void) | undefined;
			if (errorHandler) {
				errorHandler(new Error('Connection failed'));
			}

			const readyHandler = mockRedisReadClient.on.mock.calls.find(
				(call: [string, ...unknown[]]) => call[0] === 'ready',
			)?.[1] as (() => void) | undefined;
			if (readyHandler) {
				readyHandler();
			}

			mockCacheReadManager.get.mockResolvedValueOnce(mockValue);

			await service.get({
				namespace: mockNamespace,
				key: mockKey,
				consistency: ConsistencyLevel.EVENTUAL,
			});

			expect(mockCacheReadManager.get).toHaveBeenCalled();
		});

		it('should log write client errors', () => {
			const errorHandler = mockRedisWriteClient.on.mock.calls.find(
				(call: [string, ...unknown[]]) => call[0] === 'error',
			)?.[1] as ((error: Error) => void) | undefined;

			if (errorHandler) {
				const error = new Error('Write client error');
				errorHandler(error);
			}

			expect(loggerErrorSpy).toHaveBeenCalledWith(
				'Write client connection error:',
				expect.any(Error),
			);
		});
	});

	describe('recent writes cleanup', () => {
		it('should clean up old entries from recentWrites map', async () => {
			mockCacheWriteManager.set.mockResolvedValueOnce(undefined);
			await service.set({
				namespace: mockNamespace,
				key: mockKey,
				value: mockValue,
			});

			jest.advanceTimersByTime(3000);

			mockCacheReadManager.get.mockResolvedValueOnce(mockValue);

			await service.get({
				namespace: mockNamespace,
				key: mockKey,
				consistency: ConsistencyLevel.EVENTUAL,
			});

			expect(mockCacheReadManager.get).toHaveBeenCalled();
			expect(mockCacheWriteManager.get).not.toHaveBeenCalled();
		});
	});

	describe('error handling', () => {
		it('should throw CONNECTION_FAILED error when master fails after replica fallback attempt', async () => {
			const errorHandler = mockRedisReadClient.on.mock.calls.find(
				(call: [string, ...unknown[]]) => call[0] === 'error',
			)?.[1] as ((error: Error) => void) | undefined;
			if (errorHandler) {
				errorHandler(new Error('Connection failed'));
			}

			mockCacheWriteManager.get.mockRejectedValueOnce(mockError);

			await expect(
				service.get({
					namespace: mockNamespace,
					key: mockKey,
					consistency: ConsistencyLevel.EVENTUAL,
				}),
			).rejects.toThrow('Cache operation failed: CONNECTION_FAILED');
		});

		it('should throw CONNECTION_FAILED error when replica fails and is already unhealthy', async () => {
			const errorHandler = mockRedisReadClient.on.mock.calls.find(
				(call: [string, ...unknown[]]) => call[0] === 'error',
			)?.[1] as ((error: Error) => void) | undefined;
			if (errorHandler) {
				errorHandler(new Error('Connection failed'));
			}
			mockCacheWriteManager.get.mockRejectedValueOnce(mockError);

			await expect(
				service.get({
					namespace: mockNamespace,
					key: mockKey,
					consistency: ConsistencyLevel.EVENTUAL,
				}),
			).rejects.toThrow('Cache operation failed: CONNECTION_FAILED');
		});

		it('should create cache error with original error', async () => {
			mockCacheWriteManager.set.mockRejectedValueOnce(mockError);

			try {
				await service.set({
					namespace: mockNamespace,
					key: mockKey,
					value: mockValue,
				});
			} catch (error) {
				expect(error).toHaveProperty('code', 'OPERATION_FAILED');
				expect(error).toHaveProperty('originalError', mockError);
			}
		});

		it('should create cache error without original error', () => {
			const createCacheError = (service as any).createCacheError.bind(service);

			const error = createCacheError({ code: 'KEY_NOT_FOUND' });

			expect(error).toHaveProperty('code', 'KEY_NOT_FOUND');
			expect(error).toHaveProperty('message', 'Cache operation failed: KEY_NOT_FOUND');

			expect(error.originalError).toBeUndefined();
		});
	});
});

