			expect(result.fbt_products?.[0]?.style_id).toBe(123456); // mockRelatedProduct1
			expect(result.fbt_products?.[1]?.style_id).toBe(789012); // mockRelatedProduct2
			expect(result.fbt_products?.[2]?.style_id).toBe(345678); // mockRelatedProduct3
		});

		it('should handle rating blending with string and numeric ratings', async () => {
			const productWithNumericRating = {
				...mockRelatedProduct1,
				style_id: 999999,
				rating_score: 4.9, // numeric rating
			};

			mockFBTService.getFrequentlyBoughtTogether.mockReset().mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [mockRelatedProduct1, productWithNumericRating],
				fallback_used: false,
			});

			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }],
				blendStrategy: BlendStrategy.RATING,
			};

			const result = await service.getEmailRecommendations({ query });

			// Numeric 4.9 should come before string "4.5"
			expect(result.fbt_products?.[0]?.style_id).toBe(999999);
			expect(result.fbt_products?.[1]?.style_id).toBe(123456);
		});

		it('should handle products with missing or zero ratings', async () => {
			const productWithoutRating = {
				...mockRelatedProduct1,
				style_id: 888888,
				rating_score: undefined,
			} as unknown as IRelatedProduct;

			const productWithZeroRating = {
				...mockRelatedProduct1,
				style_id: 777777,
				rating_score: '0',
			};

			mockFBTService.getFrequentlyBoughtTogether.mockReset().mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [
					mockRelatedProduct1,
					productWithoutRating,
					productWithZeroRating,
				],
				fallback_used: false,
			});

			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }],
				blendStrategy: BlendStrategy.RATING,
			};

			const result = await service.getEmailRecommendations({ query });

			// Product with rating 4.5 should come first, then products with 0 or undefined ratings
			expect(result.fbt_products?.[0]?.rating_score).toBe('4.5');
		});
	});

	describe('Fallback Products', () => {
		it('should add fallback products when insufficient recommendations', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }],
				limit: 6,
			};

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [mockRelatedProduct1],
				fallback_used: false,
			});

			const mockMvRecord1 = {
				style_id: 176100,
				colors: [
					{ id: 123, name: 'Red', rbgs: [{ R: 255, G: 0, B: 0 }], image_url: null },
				],
			};
			const mockMvRecord2 = {
				style_id: 1000200,
				colors: [
					{ id: 456, name: 'Blue', rbgs: [{ R: 0, G: 0, B: 255 }], image_url: null },
				],
			};

			mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
				products: [mockRelatedProduct2, { ...mockRelatedProduct2, style_id: 1000200 }],
				mvRecords: new Map([
					[176100, mockMvRecord1 as any],
					[1000200, mockMvRecord2 as any],
				]),
			});
			mockProductHydrationService.convertMvColorsToProductColors.mockReturnValue([
				{ id: 123, name: 'Red', rbgs: [{ R: 255, G: 0, B: 0 }] },
			]);

			const result = await service.getEmailRecommendations({ query });

			expect(result.fallback_used).toBe(true);
			expect(result.fallback_reasons?.[RecommendationType.FBT]).toContain(
				'Insufficient fbt recommendations',
			);
			expect(result.fbt_products?.length).toBeGreaterThan(1);
		});

		it('should handle fallback product fetch errors', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }],
				limit: 6,
			};

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [],
				fallback_used: false,
			});

			mockProductHydrationService.hydrateProductsWithColors.mockRejectedValue(
				new Error('Product hydration error'),
			);

			const result = await service.getEmailRecommendations({ query });

			expect(result.fallback_used).toBe(true);
			expect(result.fbt_products).toHaveLength(0);
		});
	});

	describe('Duplicate Removal and Source Exclusion', () => {
		it('should remove duplicate products and exclude source products', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }],
			};

			const duplicateProduct = { ...mockRelatedProduct1 }; // Same style_id
			const sourceProduct = { ...mockRelatedProduct1, style_id: 12345 }; // Source product

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [
					mockRelatedProduct1,
					duplicateProduct,
					sourceProduct,
					mockRelatedProduct2,
				],
				fallback_used: false,
			});

			const result = await service.getEmailRecommendations({ query });

			expect(result.fbt_products).toHaveLength(2);
			expect(result.fbt_products?.find((p) => p.style_id === 12345)).toBeUndefined();
			expect(result.fbt_products?.filter((p) => p.style_id === 123456)).toHaveLength(1);
		});
	});

	describe('Error Handling', () => {
		it('should handle and re-throw service errors', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }],
			};

			const serviceError = new Error('Critical service error');
			mockFBTService.getFrequentlyBoughtTogether.mockRejectedValue(serviceError);

			const result = await service.getEmailRecommendations({ query });
			expect(result.fallback_used).toBe(true);
			expect(result.fallback_reasons?.[RecommendationType.FBT]).toContain(
				'FBT service failed',
			);
			expect(result.fbt_products).toHaveLength(0);
		});

		it('should handle FBT service failure with multiple products', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }, { productId: 67890 }],
			};

			mockFBTService.getFrequentlyBoughtTogether.mockRejectedValue(
				new Error('Service error'),
			);

			const result = await service.getEmailRecommendations({ query });
			expect(result.fallback_used).toBe(true);
			expect(result.fallback_reasons?.[RecommendationType.FBT]).toBe(
				'FBT service failed',
			);
		});

		it('should handle Similar recommendations service failure', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.SIMILAR],
				products: [{ productId: 12345 }],
			};

			mockRelatedProductsService.getRelatedProducts.mockRejectedValue(
				new Error('Similar service error'),
			);

			const result = await service.getEmailRecommendations({ query });
			expect(result.fallback_used).toBe(true);
			expect(result.fallback_reasons?.[RecommendationType.SIMILAR]).toBe(
				'Similar recommendations failed',
			);
		});
	});

	describe('Limit Handling', () => {
		it('should respect the limit parameter', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }],
				limit: 2,
			};

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [
					mockRelatedProduct1,
					mockRelatedProduct2,
					mockRelatedProduct3,
				],
				fallback_used: false,
			});

			const result = await service.getEmailRecommendations({ query });

			expect(result.fbt_products).toHaveLength(2);
		});

		it('should use default limit when not specified', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }],
			};

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: Array(10)
					.fill(mockRelatedProduct1)
					.map((p) => ({
						...p,
						style_id: Math.random() * 1000000,
					})),
				fallback_used: false,
			});

			const result = await service.getEmailRecommendations({ query });

			expect(result.fbt_products?.length ?? 0).toBeLessThanOrEqual(6); // Default limit
		});
	});

	describe('Unsupported Recommendation Types (lines 81-82)', () => {
		it('should skip unsupported recommendation type and log warning', async () => {
			const loggerWarnSpy = jest.spyOn(Logger.prototype, 'warn');
			const query: EmailRecommendationsQueryDto = {
				types: ['INVALID_TYPE' as RecommendationType, RecommendationType.FBT],
				products: [{ productId: 12345 }],
			};

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [mockRelatedProduct1],
				fallback_used: false,
			});

			const result = await service.getEmailRecommendations({ query });

			expect(loggerWarnSpy).toHaveBeenCalledWith('Unsupported recommendation type', {
				type: 'INVALID_TYPE',
			});
			expect(result.fbt_products).toBeDefined();
		});

		it('should handle only unsupported types gracefully', async () => {
			const loggerWarnSpy = jest.spyOn(Logger.prototype, 'warn');
			const query: EmailRecommendationsQueryDto = {
				types: ['UNKNOWN' as RecommendationType],
				products: [{ productId: 12345 }],
			};

			const result = await service.getEmailRecommendations({ query });

			expect(loggerWarnSpy).toHaveBeenCalledWith('Unsupported recommendation type', {
				type: 'UNKNOWN',
			});
			expect(result.fbt_products).toBeUndefined();
			expect(result.similar_products).toBeUndefined();
			expect(result.trending_products).toBeUndefined();
		});

		it('should continue processing valid types after encountering invalid type', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [
					'INVALID1' as RecommendationType,
					RecommendationType.SIMILAR,
					'INVALID2' as RecommendationType,
				],
				products: [{ productId: 12345 }],
			};

			mockRelatedProductsService.getRelatedProducts.mockResolvedValue({
				related_products: [mockRelatedProduct1],
				mms_fallback: false,
				product_id: '12345',
				color_id: null,
			});

			const result = await service.getEmailRecommendations({ query });

			expect(result.similar_products).toBeDefined();
			expect(result.similar_products).toHaveLength(1);
		});
	});

	describe('Blending Strategy Edge Cases', () => {
		it('should handle round-robin blending with empty recommendations', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }, { productId: 67890 }],
				blendStrategy: BlendStrategy.ROUND_ROBIN,
			};

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345, 67890],
				frequently_bought_together: [mockRelatedProduct1],
				fallback_used: false,
			});

			const result = await service.getEmailRecommendations({ query });
			expect(result.fbt_products).toHaveLength(1);
			expect(result.fbt_products?.[0]?.style_id).toBe(mockRelatedProduct1.style_id);
		});

		it('should handle round-robin blending with null/undefined recommendations and duplicates', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }],
				blendStrategy: BlendStrategy.ROUND_ROBIN,
			};

			// Create a product with same style_id to test duplicate filtering
			const duplicateProduct = {
				...mockRelatedProduct1,
				style_id: mockRelatedProduct1.style_id,
			};

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [
					mockRelatedProduct1,
					null as any,
					duplicateProduct,
					undefined as any,
				],
				fallback_used: false,
			});

			const result = await service.getEmailRecommendations({ query });
			expect(result.fbt_products?.length ?? 0).toBe(1); // Only one unique product
			expect(result.fbt_products?.[0]?.style_id).toBe(mockRelatedProduct1.style_id);
		});

		it('should handle rating-based sorting with string ratings that parse to 0', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }],
				blendStrategy: BlendStrategy.RATING,
			};

			const productWithInvalidRating = {
				...mockRelatedProduct1,
				style_id: 99999,
				rating_score: 'invalid-rating', // String that will parse to 0
			};

			const productWithValidRating = {
				...mockRelatedProduct2,
				style_id: 88888,
				rating_score: '4.5', // String that will parse to 4.5
			};

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [productWithInvalidRating, productWithValidRating],
				fallback_used: false,
			});

			const result = await service.getEmailRecommendations({ query });
			expect(result.fbt_products).toHaveLength(2);
			// Product with valid rating should come first
			expect(result.fbt_products?.[0]?.style_id).toBe(88888);
			expect(result.fbt_products?.[1]?.style_id).toBe(99999);
		});

		it('should use default blendStrategy parameter when not specified', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }],
				// blendStrategy not specified, should default to RATING
			};

			const productWithLowRating = {
				...mockRelatedProduct1,
				style_id: 11111,
				rating_score: 2.0,
			};

			const productWithHighRating = {
				...mockRelatedProduct2,
				style_id: 22222,
				rating_score: 4.8,
			};

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [productWithLowRating, productWithHighRating],
				fallback_used: false,
			});

			const result = await service.getEmailRecommendations({ query });
			expect(result.fbt_products).toHaveLength(2);
			// Should be sorted by rating (high to low) since default is RATING strategy
			expect(result.fbt_products?.[0]?.style_id).toBe(22222); // Higher rating first
			expect(result.fbt_products?.[1]?.style_id).toBe(11111); // Lower rating second
		});
	});

	describe('ColorId Resolution', () => {
		it('should resolve productId from colorId when productId is not provided', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ colorId: 123 }],
			};

			mockStyleColorsService.getStyleByColorId.mockResolvedValue({
				_id: 'test-id',
				style_id: 12345,
				color_id: 123,
				color_rgb: '#FF0000',
				color_name: 'Red',
				is_active: true,
				created_at: new Date(),
				updated_at: new Date(),
				deleted_at: null,
				image_url: 'test-image-url',
			});

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [mockRelatedProduct1],
				fallback_used: false,
			});

			const result = await service.getEmailRecommendations({ query });
			expect(mockStyleColorsService.getStyleByColorId).toHaveBeenCalledWith({
				colorId: 123,
