				types: [RecommendationType.FBT],
				products: [{ colorId: 999 }, { productId: 12345 }],
			};

			mockStyleColorsService.getStyleByColorId.mockResolvedValue(null);

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [mockRelatedProduct1],
				fallback_used: false,
			});

			const result = await service.getEmailRecommendations({ query });
			expect(mockStyleColorsService.getStyleByColorId).toHaveBeenCalledWith({
				colorId: 999,
			});

			expect(result.source_product_ids).toEqual([12345]);
		});

		it('should skip product when style_id is invalid (NaN)', async () => {
