				types: [RecommendationType.FBT],
				products: [{ colorId: 456 }, { productId: 12345 }],
			};

			mockStyleColorsService.getStyleByColorId.mockResolvedValue({
				_id: 'test-id',
				style_id: 'invalid-number' as unknown as number,
				color_id: 456,
				color_rgb: '#00FF00',
				color_name: 'Green',
				is_active: true,
				created_at: new Date(),
				updated_at: new Date(),
				deleted_at: null,
				image_url: 'test-image-url',
			});

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [mockRelatedProduct1],
				fallback_used: false,
			});

			const result = await service.getEmailRecommendations({ query });
			expect(mockStyleColorsService.getStyleByColorId).toHaveBeenCalledWith({
				colorId: 456,
			});

			expect(result.source_product_ids).toEqual([12345]);
		});

		it('should handle errors during colorId resolution', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ colorId: 789 }, { productId: 12345 }],
			};

			mockStyleColorsService.getStyleByColorId.mockRejectedValue(
				new Error('Database connection error'),
			);

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [mockRelatedProduct1],
				fallback_used: false,
			});

			const result = await service.getEmailRecommendations({ query });
			expect(mockStyleColorsService.getStyleByColorId).toHaveBeenCalledWith({
				colorId: 789,
			});

			expect(result.source_product_ids).toEqual([12345]);
		});

		it('should handle products with both productId and colorId', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345, colorId: 123 }],
			};

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [mockRelatedProduct1],
				fallback_used: false,
			});

			const result = await service.getEmailRecommendations({ query });
			expect(mockStyleColorsService.getStyleByColorId).not.toHaveBeenCalled();
			expect(result.source_product_ids).toEqual([12345]);
		});
	});

	describe('Unsupported Recommendation Type', () => {
		it('should warn and skip unsupported recommendation types', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: ['invalid_type' as any],
				products: [{ productId: 12345 }],
			};

			const result = await service.getEmailRecommendations({ query });
			expect(result.fbt_products).toBeUndefined();
			expect(result.similar_products).toBeUndefined();
			expect(result.trending_products).toBeUndefined();
		});
	});

	describe('Fallback Products Edge Cases', () => {
		it('should return empty array when fallback hydration returns empty products (lines 464-468)', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }],
				limit: 6,
			};

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [],
				fallback_used: false,
			});

			mockProductHydrationService.hydrateProductsWithColors.mockResolvedValue({
				products: [],
				mvRecords: new Map(),
			});

			const result = await service.getEmailRecommendations({ query });

			expect(result.fallback_used).toBe(true);
			expect(result.fbt_products).toHaveLength(0);
		});
	});

	describe('Duplicate Detection Edge Cases', () => {
		it('should filter out duplicate style_ids in recommendations (line 494)', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }],
			};

			const product1 = { ...mockRelatedProduct1, style_id: 111111 };
			const product2 = { ...mockRelatedProduct2, style_id: 222222 };
			const duplicate1 = { ...mockRelatedProduct1, style_id: 111111, name: 'Duplicate' };

			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345],
				frequently_bought_together: [product1, product2, duplicate1],
				fallback_used: false,
			});

			const result = await service.getEmailRecommendations({ query });

			expect(result.fbt_products).toHaveLength(2);
			const styleIds = result.fbt_products?.map((p) => p.style_id) ?? [];
			expect(styleIds.filter((id) => id === 111111)).toHaveLength(1);
		});
	});
});

