				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }, { productId: 67890 }],
			};

			const result = await service.getEmailRecommendations({ query });

			// Should be sorted by rating: 4.8, 4.5, 4.2
			expect(result.fbt_products?.[0]?.rating_score).toBe('4.8');
			expect(result.fbt_products?.[1]?.rating_score).toBe('4.5');
			expect(result.fbt_products?.[2]?.rating_score).toBe('4.2');
		});

		it('should use round robin blending strategy when specified', async () => {
			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }, { productId: 67890 }],
				blendStrategy: BlendStrategy.ROUND_ROBIN,
			};

			const result = await service.getEmailRecommendations({ query });

			// Round robin should alternate between products
			// First from product 12345: mockRelatedProduct1
			// First from product 67890: mockRelatedProduct2
			// Second from product 67890: mockRelatedProduct3
			expect(result.fbt_products?.[0]?.style_id).toBe(123456); // mockRelatedProduct1
			expect(result.fbt_products?.[1]?.style_id).toBe(789012); // mockRelatedProduct2
			expect(result.fbt_products?.[2]?.style_id).toBe(345678); // mockRelatedProduct3
		});

		it('should handle rating blending with string and numeric ratings', async () => {
			const productWithNumericRating = {
				...mockRelatedProduct1,
				style_id: 999999,
				rating_score: 4.9, // numeric rating
			};

			mockFBTService.getFrequentlyBoughtTogether.mockReset().mockResolvedValue({
