import { BadRequestException, Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { StyleColorsService } from '@modules/db/style-colors/style-colors.service';
import { StylesService } from '@modules/db/styles/styles.service';
import { ProductHydrationService } from '@modules/product-hydration/product-hydration.service';
import { EmailRecommendationsService } from '@modules/rest/email-recommendations/email-recommendations.service';
import { FrequentlyBoughtTogetherService } from '@modules/rest/frequently-bought-together/frequently-bought-together.service';
import { RelatedProductsService } from '@modules/rest/related-products/related-products.service';
import { TrendingProductsService } from '@modules/rest/trending-products/trending-products.service';

import { IRelatedProduct } from '@interfaces/related-product.interface';

import {
	EmailRecommendationsQueryDto,
	RecommendationType,
	BlendStrategy,
} from '@dto/email-recommendations/email-recommendations-query.dto';

import { createMockStyle } from '../test-helpers/mock-factories';

jest.mock('@utils/random-color-picker.util', () => ({
	assignRandomColorToProduct: jest.fn(({ product }) => product),
}));

describe('EmailRecommendationsService', () => {
	let service: EmailRecommendationsService;
	let mockProductHydrationService: jest.Mocked<ProductHydrationService>;
	let mockStylesService: jest.Mocked<StylesService>;
	let mockStyleColorsService: jest.Mocked<StyleColorsService>;
	let mockFBTService: jest.Mocked<FrequentlyBoughtTogetherService>;
	let mockRelatedProductsService: jest.Mocked<RelatedProductsService>;
	let mockTrendingProductsService: jest.Mocked<TrendingProductsService>;

	const mockRelatedProduct1: IRelatedProduct = {
		style_id: 123456,
		name: 'Test Product 1',
		link: '/products/test-product-1',
		image_src: 'https://example.com/test-product-1.jpg',
		color: 1521505,
		sizing: 'S-XL',
		sizes: ['S', 'M', 'L', 'XL'],
		min_qty: 25,
		complement_badge: null,
		rating_score: '4.5',
		rating_count: '100',
		decoration_method: 'screen',
		primary_category_id: 37,
		primary_category_name: 'T-Shirts',
		default_quote_qty: 100,
		style_type: 'apparel',
		broad_category_names: ['Apparel', 'T-Shirts'],
		sub_category_names: ['Short Sleeve T-Shirts'],
		turn_time: 14,
		rush_turn_time: 7,
		default_unit_prices: [
			{ algorithm: 'default-2022-03-24', quantity: 100, price: '15.95' },
		],
		brand: ['Gildan'],
	};

	const mockRelatedProduct2: IRelatedProduct = {
		...mockRelatedProduct1,
		style_id: 789012,
		name: 'Test Product 2',
		rating_score: '4.8',
		rating_count: '200',
	};

	const mockRelatedProduct3: IRelatedProduct = {
		...mockRelatedProduct1,
		style_id: 345678,
		name: 'Test Product 3',
		rating_score: '4.2',
		rating_count: '50',
	};

	const mockStyle = createMockStyle({
		_id: '507f1f77bcf86cd799439011',
		style_id: 12345,
		primary_category_id: 37,
		root_category_id: 1,
		purchases_count: 100,
		categories_ids: [37, 38],
		categories_with_parents_ids: [1, 37, 38],
	});

	beforeEach(async () => {
		mockProductHydrationService = {
			hydrateProductsWithColors: jest.fn(),
			convertMvColorsToProductColors: jest.fn(),
		} as unknown as jest.Mocked<ProductHydrationService>;

		mockStylesService = {
			getStylesByIds: jest.fn(),
		} as unknown as jest.Mocked<StylesService>;

		mockStyleColorsService = {
			getStyleByColorId: jest.fn(),
		} as unknown as jest.Mocked<StyleColorsService>;

		mockFBTService = {
			getFrequentlyBoughtTogether: jest.fn(),
		} as unknown as jest.Mocked<FrequentlyBoughtTogetherService>;

		mockRelatedProductsService = {
			getRelatedProducts: jest.fn(),
		} as unknown as jest.Mocked<RelatedProductsService>;

		mockTrendingProductsService = {
			getTrendingProductsByCategory: jest.fn(),
		} as unknown as jest.Mocked<TrendingProductsService>;

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				EmailRecommendationsService,
				{
					provide: ProductHydrationService,
					useValue: mockProductHydrationService,
				},
				{
					provide: StylesService,
					useValue: mockStylesService,
				},
				{
					provide: StyleColorsService,
					useValue: mockStyleColorsService,
				},
				{
					provide: FrequentlyBoughtTogetherService,
					useValue: mockFBTService,
				},
				{
					provide: RelatedProductsService,
					useValue: mockRelatedProductsService,
				},
				{
					provide: TrendingProductsService,
					useValue: mockTrendingProductsService,
				},
			],
		}).compile();

		service = module.get<EmailRecommendationsService>(EmailRecommendationsService);

		jest.spyOn(Logger.prototype, 'log').mockImplementation();
		jest.spyOn(Logger.prototype, 'warn').mockImplementation();
		jest.spyOn(Logger.prototype, 'error').mockImplementation();
	});

	afterEach(() => {
		jest.clearAllMocks();
	});

	describe('getEmailRecommendations', () => {
		describe('FBT Recommendations', () => {
			it('should return FBT recommendations successfully', async () => {
				const query: EmailRecommendationsQueryDto = {
					types: [RecommendationType.FBT],
					products: [{ productId: 12345 }],
					limit: 6,
				};

				mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
					style_ids: [12345],
					frequently_bought_together: [mockRelatedProduct1, mockRelatedProduct2],
					fallback_used: false,
				});

				const result = await service.getEmailRecommendations({ query });

				expect(result.fbt_products).toBeDefined();
				expect(result.fbt_products?.length).toBe(2);
				expect(result.source_product_ids).toEqual([12345]);
				expect(result.fallback_used).toBe(true);
				expect(result.fallback_reasons?.[RecommendationType.FBT]).toBe(
					'Insufficient fbt recommendations, added fallback products',
				);
				expect(mockFBTService.getFrequentlyBoughtTogether).toHaveBeenCalledWith({
					query: {
						styleIds: [12345],
						exclude: [12345],
					},
				});
			});

			it('should handle FBT recommendations with color ID', async () => {
				const query: EmailRecommendationsQueryDto = {
					types: [RecommendationType.FBT],
					products: [{ productId: 12345, colorId: 123 }],
				};

				mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
					style_ids: [12345],
					frequently_bought_together: [mockRelatedProduct1],
					fallback_used: false,
				});

				const result = await service.getEmailRecommendations({ query });

				expect(result.fbt_products).toBeDefined();
				expect(mockFBTService.getFrequentlyBoughtTogether).toHaveBeenCalledWith({
					query: {
						styleIds: [12345],
						exclude: [12345],
					},
				});
			});

			it('should handle multiple products for FBT recommendations', async () => {
				const query: EmailRecommendationsQueryDto = {
					types: [RecommendationType.FBT],
					products: [{ productId: 12345 }, { productId: 67890 }],
				};

				mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
					style_ids: [12345, 67890],
					frequently_bought_together: [mockRelatedProduct1, mockRelatedProduct2],
					fallback_used: false,
				});

				const result = await service.getEmailRecommendations({ query });

				expect(result.fbt_products).toBeDefined();
				expect(result.source_product_ids).toEqual([12345, 67890]);
				expect(mockFBTService.getFrequentlyBoughtTogether).toHaveBeenCalledTimes(1);
				expect(mockFBTService.getFrequentlyBoughtTogether).toHaveBeenCalledWith({
					query: {
						styleIds: [12345, 67890],
						exclude: [12345, 67890],
					},
				});
			});

			it('should throw BadRequestException when no products provided for FBT', async () => {
				const query: EmailRecommendationsQueryDto = {
					types: [RecommendationType.FBT],
					products: [],
				};

				await expect(service.getEmailRecommendations({ query })).rejects.toThrow(
					BadRequestException,
				);
				await expect(service.getEmailRecommendations({ query })).rejects.toThrow(
					'Products are required for FBT recommendations',
				);
			});

			it('should handle FBT service fallback', async () => {
				const query: EmailRecommendationsQueryDto = {
					types: [RecommendationType.FBT],
