				fallback_used: false,
			});

			const query: EmailRecommendationsQueryDto = {
				types: [RecommendationType.FBT],
				products: [{ productId: 12345 }],
				blendStrategy: BlendStrategy.RATING,
			};

			const result = await service.getEmailRecommendations({ query });

			// Product with rating 4.5 should come first, then products with 0 or undefined ratings
			expect(result.fbt_products?.[0]?.rating_score).toBe('4.5');
		});
	});

