	describe('Blending Strategies', () => {
		beforeEach(() => {
			// Setup multiple products with different ratings for blending tests
			mockFBTService.getFrequentlyBoughtTogether.mockResolvedValue({
				style_ids: [12345, 67890],
				frequently_bought_together: [
					mockRelatedProduct1,
					mockRelatedProduct2,
