					primary_category_id: 10,
					edge_id: 50,
					edge_weight: 0.5,
					created_at: new Date(),
					updated_at: new Date(),
					deleted_at: null,
				},
			];
			jest
				.spyOn(categoryCorrelationsService, 'getTopCorrelatedCategories')
				.mockResolvedValue(fourCorrelations);
			jest.spyOn(stylesService, 'getMostPopularStylesByCategories').mockResolvedValue([
				{ primary_category_id: 20, style_id: 200, purchases_count: 100 },
				{ primary_category_id: 30, style_id: 300, purchases_count: 80 },
				{ primary_category_id: 40, style_id: 400, purchases_count: 60 },
				{ primary_category_id: 50, style_id: 500, purchases_count: 40 },
			] as IStyleBase[]);

			const fourProducts: IRelatedProduct[] = [
				{ ...mockRelatedProducts[0]!, style_id: 200 },
				{ ...mockRelatedProducts[1]!, style_id: 300 },
				{ ...mockRelatedProducts[2]!, style_id: 400 },
				{ ...mockRelatedProducts[0]!, style_id: 500 },
			];
			jest
				.spyOn(productHydrationService, 'hydrateProducts')
				.mockResolvedValue(fourProducts);

			const response = await request(getHttpServer)
				.get('/frequently-bought-together?styleIds=123456')
				.expect(200);

			const body = response.body as FrequentlyBoughtTogetherResponseDto;
			expect(body).toHaveProperty('style_ids', [123456]);
			expect(body.frequently_bought_together.length).toBeGreaterThanOrEqual(3);
		});
	});

	describe('GET /frequently-bought-together/v2', () => {
		const testStyleId = 123456;

		it('should return co-purchased products when copurchases exist', async () => {
			jest.spyOn(stylesService, 'getStyleById').mockResolvedValue(mockStyle as any);
			jest.spyOn(styleCopurchasesService, 'getTopCopurchases').mockResolvedValue([
				{ paired_style_id: 200, copurchase_count: 10 },
				{ paired_style_id: 300, copurchase_count: 5 },
			]);
			jest
				.spyOn(styleColorsService, 'getStyleByStyleId')
				.mockResolvedValue(mockStyleColor as any);

			const response = await request(getHttpServer)
				.get(`/frequently-bought-together/v2?styleId=${testStyleId}`)
				.expect(200);

			const body = response.body as FrequentlyBoughtTogetherV2ResponseDto;
			expect(body).toHaveProperty('style_id', testStyleId);
			expect(body).toHaveProperty('fallback_used', false);
			expect(Array.isArray(body.frequently_bought_together)).toBe(true);
		});

		it('should return co-purchased products with colorId', async () => {
			jest.spyOn(stylesService, 'getStyleById').mockResolvedValue(mockStyle as any);
			jest
				.spyOn(styleCopurchasesService, 'getTopCopurchases')
				.mockResolvedValue([{ paired_style_id: 200, copurchase_count: 10 }]);
			jest
				.spyOn(styleColorsService, 'getStyleByStyleAndColorId')
				.mockResolvedValue(mockStyleColor as any);

			const response = await request(getHttpServer)
				.get(`/frequently-bought-together/v2?styleId=${testStyleId}&colorId=100`)
				.expect(200);

			const body = response.body as FrequentlyBoughtTogetherV2ResponseDto;
			expect(body).toHaveProperty('style_id', testStyleId);
			expect(body).toHaveProperty('fallback_used', false);
		});

		it('should fall back to v1 when no copurchases exist', async () => {
			jest.spyOn(stylesService, 'getStyleById').mockResolvedValue(mockStyle as any);
			jest.spyOn(styleCopurchasesService, 'getTopCopurchases').mockResolvedValue([]);
			jest
				.spyOn(categoryCorrelationsService, 'getTopCorrelatedCategories')
				.mockResolvedValue(mockCategoryCorrelations as any);
			jest
				.spyOn(stylesService, 'getMostPopularStylesByCategories')
				.mockResolvedValue(mockPopularStyles as any);
			jest
				.spyOn(styleColorsService, 'getStyleByStyleId')
				.mockResolvedValue(mockStyleColor as any);

			const response = await request(getHttpServer)
				.get(`/frequently-bought-together/v2?styleId=${testStyleId}`)
				.expect(200);

			const body = response.body as FrequentlyBoughtTogetherV2ResponseDto;
			expect(body).toHaveProperty('style_id', testStyleId);
			expect(body).toHaveProperty('fallback_used', true);
		});

		it('should return 400 when styleId is missing', async () => {
			await request(getHttpServer).get('/frequently-bought-together/v2').expect(400);
		});

		it('should return 400 when style is not found', async () => {
			jest.spyOn(stylesService, 'getStyleById').mockResolvedValue(null);

			await request(getHttpServer)
				.get('/frequently-bought-together/v2?styleId=999999')
				.expect(400);
		});

		it('should return diversified copurchases with unique categories when diversifyCategories=true', async () => {
			jest.spyOn(stylesService, 'getStyleById').mockResolvedValue(mockStyle as any);
			jest
				.spyOn(styleCopurchasesService, 'getTopCopurchasesDiversified')
				.mockResolvedValue([
					{
						paired_style_id: 200,
						copurchase_count: 10,
						primary_category_id: 20,
						style_type: 'apparel',
					},
					{
						paired_style_id: 300,
						copurchase_count: 8,
						primary_category_id: 30,
						style_type: 'apparel',
					},
					{
						paired_style_id: 400,
						copurchase_count: 5,
						primary_category_id: 40,
						style_type: 'non-apparel',
					},
				]);

			const response = await request(getHttpServer)
				.get(
					`/frequently-bought-together/v2?styleId=${testStyleId}&diversifyCategories=true`,
				)
				.expect(200);

			const body = response.body as FrequentlyBoughtTogetherV2ResponseDto;
			expect(body).toHaveProperty('style_id', testStyleId);
			expect(body).toHaveProperty('fallback_used', false);
			expect(Array.isArray(body.frequently_bought_together)).toBe(true);
			expect(styleCopurchasesService.getTopCopurchasesDiversified).toHaveBeenCalledWith(
				expect.objectContaining({
					styleId: testStyleId,
					diversifyCategories: true,
					favorOppositeType: false,
				}),
			);
		});

		it('should prioritize opposite type when favorOppositeType=true', async () => {
			jest.spyOn(stylesService, 'getStyleById').mockResolvedValue(mockStyle as any);
			jest
				.spyOn(styleCopurchasesService, 'getTopCopurchasesDiversified')
				.mockResolvedValue([
					{
						paired_style_id: 400,
						copurchase_count: 5,
						primary_category_id: 40,
						style_type: 'non-apparel',
					},
					{
						paired_style_id: 200,
						copurchase_count: 10,
						primary_category_id: 20,
						style_type: 'apparel',
					},
				]);

			const response = await request(getHttpServer)
				.get(
					`/frequently-bought-together/v2?styleId=${testStyleId}&favorOppositeType=true`,
				)
				.expect(200);

			const body = response.body as FrequentlyBoughtTogetherV2ResponseDto;
			expect(body).toHaveProperty('style_id', testStyleId);
			expect(body).toHaveProperty('fallback_used', false);
			expect(styleCopurchasesService.getTopCopurchasesDiversified).toHaveBeenCalledWith(
				expect.objectContaining({
					styleId: testStyleId,
					diversifyCategories: false,
					favorOppositeType: true,
					seedStyleType: 'apparel',
				}),
			);
		});

		it('should handle both diversifyCategories and favorOppositeType combined', async () => {
			jest.spyOn(stylesService, 'getStyleById').mockResolvedValue(mockStyle as any);
			jest
				.spyOn(styleCopurchasesService, 'getTopCopurchasesDiversified')
				.mockResolvedValue([
					{
						paired_style_id: 400,
						copurchase_count: 5,
						primary_category_id: 40,
						style_type: 'non-apparel',
					},
					{
						paired_style_id: 200,
						copurchase_count: 10,
						primary_category_id: 20,
						style_type: 'apparel',
					},
				]);

			const response = await request(getHttpServer)
				.get(
					`/frequently-bought-together/v2?styleId=${testStyleId}&diversifyCategories=true&favorOppositeType=true`,
				)
				.expect(200);

			const body = response.body as FrequentlyBoughtTogetherV2ResponseDto;
			expect(body).toHaveProperty('style_id', testStyleId);
			expect(body).toHaveProperty('fallback_used', false);
			expect(styleCopurchasesService.getTopCopurchasesDiversified).toHaveBeenCalledWith(
				expect.objectContaining({
					diversifyCategories: true,
					favorOppositeType: true,
					seedStyleType: 'apparel',
				}),
			);
		});

		it('should fall back to v1 when diversified copurchases return empty', async () => {
			jest.spyOn(stylesService, 'getStyleById').mockResolvedValue(mockStyle as any);
			jest
				.spyOn(styleCopurchasesService, 'getTopCopurchasesDiversified')
				.mockResolvedValue([]);
			jest
				.spyOn(categoryCorrelationsService, 'getTopCorrelatedCategories')
				.mockResolvedValue(mockCategoryCorrelations as any);
			jest
				.spyOn(stylesService, 'getMostPopularStylesByCategories')
				.mockResolvedValue(mockPopularStyles as any);

			const response = await request(getHttpServer)
				.get(
					`/frequently-bought-together/v2?styleId=${testStyleId}&diversifyCategories=true`,
				)
				.expect(200);

			const body = response.body as FrequentlyBoughtTogetherV2ResponseDto;
			expect(body).toHaveProperty('style_id', testStyleId);
			expect(body).toHaveProperty('fallback_used', true);
		});

		it('should default to existing behavior when no new params are set', async () => {
			jest.spyOn(stylesService, 'getStyleById').mockResolvedValue(mockStyle as any);
			jest.spyOn(styleCopurchasesService, 'getTopCopurchases').mockResolvedValue([
				{ paired_style_id: 200, copurchase_count: 10 },
				{ paired_style_id: 300, copurchase_count: 5 },
			]);

			const response = await request(getHttpServer)
				.get(`/frequently-bought-together/v2?styleId=${testStyleId}`)
				.expect(200);

			const body = response.body as FrequentlyBoughtTogetherV2ResponseDto;
			expect(body).toHaveProperty('style_id', testStyleId);
			expect(body).toHaveProperty('fallback_used', false);
			expect(styleCopurchasesService.getTopCopurchases).toHaveBeenCalled();
			expect(styleCopurchasesService.getTopCopurchasesDiversified).not.toHaveBeenCalled();
		});

		it('should handle favorOppositeType with null seedStyleType from styles_mv', async () => {
			jest.spyOn(stylesService, 'getStyleById').mockResolvedValue(mockStyle as any);

			const stylesMvService = app.get(StylesMvService);
			jest.spyOn(stylesMvService, 'getByStyleId').mockResolvedValue(null);

			jest
				.spyOn(styleCopurchasesService, 'getTopCopurchasesDiversified')
				.mockResolvedValue([
					{
						paired_style_id: 200,
						copurchase_count: 10,
						primary_category_id: 20,
						style_type: 'apparel',
					},
				]);

			const response = await request(getHttpServer)
				.get(
					`/frequently-bought-together/v2?styleId=${testStyleId}&favorOppositeType=true`,
				)
				.expect(200);

			const body = response.body as FrequentlyBoughtTogetherV2ResponseDto;
			expect(body).toHaveProperty('fallback_used', false);
			expect(styleCopurchasesService.getTopCopurchasesDiversified).toHaveBeenCalledWith(
				expect.objectContaining({
					seedStyleType: null,
				}),
			);
		});
	});
});

