				`Successfully generated features for style ${testStyle.id} using reduced fields`,
			);
			expect(openAIService.generateProductFeatures).toHaveBeenCalledTimes(2);
		});

		it('should handle non-Error thrown exceptions with token limit', async () => {
			const testStyle = { ...mockStyle };

			jest.spyOn(service as any, 'extractFeaturesRelatedFields').mockReturnValue({
				name: 'Test Product',
				manufacturer: 'Test Manufacturer',
			});

			jest.spyOn(service as any, 'createHash').mockResolvedValue(undefined);
			jest.spyOn(service as any, 'saveStyleToDatabase').mockResolvedValue(undefined);
			jest.spyOn(service as any, 'saveCondensedFeatures').mockResolvedValue(undefined);

			openAIService.generateProductFeatures
				.mockRejectedValueOnce("This model's maximum context length is 128000 tokens")
				.mockResolvedValueOnce({
					description: ['reduced_feature1'],
				});

			const result = await service.process({ style: testStyle, allCategories: [] });

			expect(result).toBe(true);
			expect(loggerWarnSpy).toHaveBeenCalledWith(
				`Token limit exceeded for style ${testStyle.id}, retrying with reduced fields`,
			);
			expect(openAIService.generateProductFeatures).toHaveBeenCalledTimes(2);
		});

		it('should fallback and return empty array when reduced result description is undefined', async () => {
			const testStyle = { ...mockStyle };

			jest.spyOn(service as any, 'extractFeaturesRelatedFields').mockReturnValue({
				name: 'Test Product',
			});

			jest.spyOn(service as any, 'createHash').mockResolvedValue(undefined);
			jest.spyOn(service as any, 'saveStyleToDatabase').mockResolvedValue(undefined);
			jest.spyOn(service as any, 'saveCondensedFeatures').mockResolvedValue(undefined);

			openAIService.generateProductFeatures
				.mockResolvedValueOnce({
					error: "This model's maximum context length is 128000 tokens",
				})
				.mockResolvedValueOnce({
					description: undefined,
				} as any);

			const result = await service.process({ style: testStyle, allCategories: [] });

			expect(result).toBe(true);
			expect(openAIService.generateProductFeatures).toHaveBeenCalledTimes(2);
		});
	});

	describe('getBroadCategoryNames edge cases', () => {
		it('should exclude taxonomy categories and excluded category names', () => {
			const categories = [
				{ id: 1, parent_id: 300, name: 'Child Taxonomy', active: true },
				{ id: 2, parent_id: 400, name: 'Child Excluded', active: true },
			] as unknown as MMSStyleCategory[];

			const allCategories: MMSAllStyleCategory[] = [
				{
					_id: 300,
					active: true,
					name: 'Some Taxonomy Category',
					parent_id: null,
				},
				{
					_id: 400,
					active: true,
					name: 'Pens & Office Supplies',
					parent_id: null,
				},
			];

			const getBroadCategoryNamesMethod = (service as any).getBroadCategoryNames.bind(
				service,
			);
			const result = getBroadCategoryNamesMethod({ categories, allCategories });

			expect(result).toEqual([]);
		});
	});

	describe('getRootCategoryId edge cases', () => {
		it('should return null when primary_category is missing', () => {
			const styleWithoutPrimary: MMSStyleToProcess = {
				...mockStyle,
				primary_category: null,
			} as MMSStyleToProcess;

			const getRootCategoryIdMethod = (service as any).getRootCategoryId.bind(service);
			const result = getRootCategoryIdMethod({
				style: styleWithoutPrimary,
				allCategories: [mockCategory],
			});

			expect(result).toBeNull();
		});

		it('should return null when primary category is not found in allCategories', () => {
			const styleWithUnknownPrimary: MMSStyleToProcess = {
				...mockStyle,
				primary_category_id: 9999,
			} as MMSStyleToProcess;

			const getRootCategoryIdMethod = (service as any).getRootCategoryId.bind(service);
			const result = getRootCategoryIdMethod({
				style: styleWithUnknownPrimary,
				allCategories: [mockCategory],
			});

			expect(result).toBeNull();
		});

		it('should traverse parent chain and return root category id', () => {
			const rootCategory: MMSAllStyleCategory = {
				_id: 1,
				active: true,
				name: 'Root',
				// @ts-ignore testing parent_id null
				parent_id: null,
			};

			const middleCategory: MMSAllStyleCategory = {
				_id: 2,
				active: true,
				name: 'Middle',
				parent_id: 1,
			};

			const leafCategory: MMSAllStyleCategory = {
				_id: 3,
				active: true,
				name: 'Leaf',
				parent_id: 2,
			};

			const styleWithLeafPrimary: MMSStyleToProcess = {
				...mockStyle,
				primary_category_id: leafCategory._id,
				primary_category: {
					id: leafCategory._id,
					active: true,
					name: leafCategory['name'] as string,
					parent_id: leafCategory['parent_id'] as number | null,
					default_quote_qty: 25,
				} as MMSStyleCategory,
			} as MMSStyleToProcess;

			const getRootCategoryIdMethod = (service as any).getRootCategoryId.bind(service);
			const result = getRootCategoryIdMethod({
				style: styleWithLeafPrimary,
				allCategories: [rootCategory, middleCategory, leafCategory],
			});

			expect(result).toBe(rootCategory._id);
		});
	});

	describe('getAllParentCategoryIds edge cases', () => {
		it('should return empty array when category has no parent', () => {
			const allCategories: MMSAllStyleCategory[] = [
				{
					_id: 10,
					active: true,
					name: 'Root Category',
					// @ts-ignore testing missing parent
					parent_id: null,
				},
			];

			const getAllParentCategoryIdsMethod = (service as any).getAllParentCategoryIds.bind(
				service,
			);
			const result = getAllParentCategoryIdsMethod({
				categoryId: 10,
				allCategories,
			});

			expect(result).toEqual([]);
		});

		it('should collect all parent ids while traversing up the tree', () => {
			const root: MMSAllStyleCategory = {
				_id: 1,
				active: true,
				name: 'Root',
				// @ts-ignore testing parent_id null
				parent_id: null,
			};

			const middle: MMSAllStyleCategory = {
				_id: 2,
				active: true,
				name: 'Middle',
				parent_id: 1,
			};

			const leaf: MMSAllStyleCategory = {
				_id: 3,
				active: true,
				name: 'Leaf',
				parent_id: 2,
			};

			const getAllParentCategoryIdsMethod = (service as any).getAllParentCategoryIds.bind(
				service,
			);
			const result = getAllParentCategoryIdsMethod({
				categoryId: leaf._id,
				allCategories: [root, middle, leaf],
			});

			expect(result).toEqual([2, 1]);
		});
	});

	describe('extractFeaturesRelatedFields edge cases', () => {
		it('should handle null turntime and has_singles_enabled_colors false', () => {
			const styleWithoutTurntime: MMSStyleToProcess = {
				...mockStyle,
				turntime: null,
				has_singles_enabled_colors: false,
				categories: [],
			} as MMSStyleToProcess;

			const extractFeaturesRelatedFieldsMethod = (
				service as any
			).extractFeaturesRelatedFields.bind(service);
			const result = extractFeaturesRelatedFieldsMethod({
				style: styleWithoutTurntime,
				allCategories: [],
			});

			expect(result.turn_time).toBe(0);
			expect(result.rush_turn_time).toBe(0);
			expect(result.no_minimum).toBe(0);
			expect(result.sub_category_names).toEqual([]);
		});
	});

	describe('getBroadCategoryNames positive cases', () => {
		it('should include non-taxonomy, non-excluded parent names', () => {
			const categories = [
				{ id: 10, parent_id: 500, name: 'Child Category', active: true },
			] as unknown as MMSStyleCategory[];

			const allCategories: MMSAllStyleCategory[] = [
				{
					_id: 500,
					active: true,
					name: 'Valid Parent',
					parent_id: null,
				},
			];

			const getBroadCategoryNamesMethod = (service as any).getBroadCategoryNames.bind(
				service,
			);
			const result = getBroadCategoryNamesMethod({ categories, allCategories });

			expect(result).toEqual(['Valid Parent']);
		});
	});

	describe('getStylesSubcategories positive cases', () => {
		it('should include leaf category names when there are no children', () => {
			const leafCategory: MMSStyleCategory = {
				id: 900,
				active: true,
				name: 'Leaf Subcategory',
				parent_id: 800,
				default_quote_qty: 25,
			};

			const allCategories: MMSAllStyleCategory[] = [
				{
					_id: 800,
					active: true,
					name: 'Parent Category',
					parent_id: null,
				},
			];

			const getStylesSubcategoriesMethod = (service as any).getStylesSubcategories.bind(
				service,
			);
			const result = getStylesSubcategoriesMethod({
				categories: [leafCategory],
				allCategories,
			});

			expect(result).toEqual(['Leaf Subcategory']);
		});
	});

	describe('saveCondensedFeatures', () => {
		let saveCondensedFeaturesMethod: (params: {
			styleId: number;
			condensedFeatures: string[];
		}) => Promise<void>;

		beforeEach(() => {
			saveCondensedFeaturesMethod = (
				service as unknown as {
					saveCondensedFeatures(params: {
						styleId: number;
						condensedFeatures: string[];
					}): Promise<void>;
				}
			).saveCondensedFeatures.bind(service);

			loggerDebugSpy.mockClear();
			loggerWarnSpy.mockClear();
			condensedFeaturesService.upsertCondensedFeature.mockClear();
		});

		it('should call upsertCondensedFeature with correct params and log debug', async () => {
			const styleId = 12345;
			const condensedFeatures = ['feature-a', 'feature-b'];

			await saveCondensedFeaturesMethod({ styleId, condensedFeatures });

			expect(condensedFeaturesService.upsertCondensedFeature).toHaveBeenCalledTimes(1);
			expect(condensedFeaturesService.upsertCondensedFeature).toHaveBeenCalledWith({
				data: { style_id: styleId, condensed_features: condensedFeatures },
			});
			expect(loggerDebugSpy).toHaveBeenCalledWith(
				`Condensed features saved for style ${styleId}: ${condensedFeatures.join(', ')}`,
			);
		});

		it('should rethrow errors from upsertCondensedFeature', async () => {
			const styleId = 99999;
			const condensedFeatures = ['feature-1'];
			const dbError = new Error('Connection refused');
			condensedFeaturesService.upsertCondensedFeature.mockRejectedValueOnce(dbError);

			await expect(
				saveCondensedFeaturesMethod({ styleId, condensedFeatures }),
			).rejects.toThrow('Connection refused');

			expect(loggerDebugSpy).not.toHaveBeenCalled();
		});
	});
});

