			mockCacheWriteManager.get.mockResolvedValueOnce(mockValue);

			const result = await service.get({
				namespace: mockNamespace,
				key: mockKey,
				consistency: ConsistencyLevel.EVENTUAL,
			});

			expect(mockCacheWriteManager.get).toHaveBeenCalledWith(mockNamespacedKey);
			expect(mockCacheReadManager.get).not.toHaveBeenCalled();
			expect(result).toEqual(mockValue);
		});

		it('should read from master for recently written keys', async () => {
			mockCacheWriteManager.set.mockResolvedValueOnce(undefined);
			await service.set({
				namespace: mockNamespace,
				key: mockKey,
				value: mockValue,
